import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _blessing_of_fervor = {title: "Blessing of Fervor", jsx: <><h2 id="spell-blessing_of_fervor-blessing-of-fervor">Blessing of Fervor</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 205</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> cleric 4, oracle 4, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>With this blessing, you call your allies to move forth and empower them to conquer and become victorious. Each round for the duration of this spell, each of your allies can choose one of the following bonuses for that round at the beginning of its turn (their choice).</p>
<ul>
<li>Increase its speed by 30 feet.</li>
<li>Stand up as a swift action without provoking an attack of opportunity.</li>
<li>Take one extra attack as part of a full attack action, using its highest base attack bonus.</li>
<li>Gain a +2 bonus on attack rolls and a +2 dodge bonus to AC and Reflex saves.</li>
<li>Cast a single spell of 2nd level or lower as if it were an <Link to="/feat/enlarged">enlarged</Link>, <Link to="/feat/extended">extended</Link>, <Link to="/feat/silent_spell">silent</Link>, or <Link to="/feat/still_spell">still spell</Link>.</li>
</ul>
<p>These effects are not cumulative with similar effects, such as those provided by haste or a speed weapon, nor do they actually grant an extra action, so you can't use it to cast a second spell or otherwise take an extra action in the round. Blessing of fervor does not stack with haste.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-blessing_of_fervor--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Blessing of Fervor</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 86</Link><br/>Affected creatures can choose two of the spell's bonuses each round rather than one.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _blessing_of_liberty = {title: "Blessing of Liberty", jsx: <><h2 id="spell-blessing_of_liberty-blessing-of-liberty">Blessing of Liberty</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 22</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> bard 2, shaman 2, skald 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a feather or small object that symbolizes good fortune)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You imbue yourself with the blessings of liberty. You gain a +1 luck bonus per 6 caster levels (minimum +1, maximum +3) to your CMD and on saving throws against spells and traps that would move you or impede your movement. You can end the spell's effects as a swift action to gain a +20 foot enhancement bonus to your base speed for 1 round per whole minute of duration remaining.</p>
</>};
const _blessing_of_luck_and_resolve = {title: "Blessing of Luck and Resolve", jsx: <><h2 id="spell-blessing_of_luck_and_resolve-blessing-of-luck-and-resolve">Blessing of Luck and Resolve</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 68</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> cleric 2, inquisitor 2, oracle 2, paladin 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one living creature touched<br/><strong>Duration</strong> 1 minute/level (d), special see below<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><blockquote>
<p><em><Link to="/race/halfling">Halflings</Link> have access to the following spells.</em></p>
</blockquote>
<p>A favored blessing of halfling clerics, this spell grants its target a +2 morale bonus on saving throws against fear effects. If the target has the fearless racial trait, it is immune to fear instead. If the target fails a saving throw against fear, it can end the spell as an immediate action to reroll the save with a +4 morale bonus, and must take the new result, even if it is worse.</p>
<h3 id="spell-blessing_of_luck_and_resolve-mass-blessing-of-luck-and-resolve">Mass Blessing of Luck and Resolve</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 68</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> cleric 6, inquisitor 6, oracle 6, paladin 4, warpriest 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 minute/level (d), special see below<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like blessing of luck and resolve, except that it affects multiple creatures.</p>
</>};
const _blessing_of_the_mole = {title: "Blessing of the Mole", jsx: <><h2 id="spell-blessing_of_the_mole-blessing-of-the-mole">Blessing of the Mole</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> cleric 3, hunter 3, inquisitor 3, oracle 3, paladin 3, ranger 3, warpriest 3<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 1 creature/level<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong>  (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The targets gain darkvision 30 feet and a +2 competence bonus on Stealth checks.</p>
</>};
const _blessing_of_the_salamander = {title: "Blessing of the Salamander", jsx: <><h2 id="spell-blessing_of_the_salamander-blessing-of-the-salamander">Blessing of the Salamander</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> druid 5, hunter 4, ranger 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>When you cast this on a creature, its skin turns slick and clammy and it is able to regenerate damage each round. While under the effects of the spell, the creature gains fast healing 5, fire resistance 20 and a +2 competence bonus to its Combat Maneuver Defense.</p>
</>};
const _blessing_of_the_watch = {title: "Blessing of the Watch", jsx: <><h2 id="spell-blessing_of_the_watch-blessing-of-the-watch">Blessing of the Watch</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 230</Link>, <Link to="/source/pathfinder_8_seven_days_to_the_grave">Pathfinder #8: Seven Days to the Grave pg. 71</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 5</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> cleric 1, inquisitor 1, oracle 1, paladin 1, warpriest 1 (Abadar; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 50 ft.<br/><strong>Area</strong> The caster and all allies within a 50-ft. burst, centered on the caster<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>This spell functions like bless, except as noted. It works only in the caster's home city, and in areas under the jurisdiction of the city watch. For example, if the watch patrols a shantytown outside the city walls but not the ruined subterranean tunnels that lie beneath the city, the spell works in the former area but not the latter.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _blight = {title: "Blight", jsx: <><h2 id="spell-blight-blight">Blight</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 250</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 5, druid 4, hunter 4, shaman 5, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> plant touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude half; see text; <strong>Spell Resistance</strong> yes</p><p>This spell withers a single plant of any size. An affected plant creature takes 1d6 points of damage per level (maximum 15d6) and may attempt a Fortitude saving throw for half damage. A plant that isn't a creature doesn't receive a save and immediately withers and dies.</p>
<p>This spell has no effect on the soil or surrounding plant life.</p>
</>};
const _blightburn_weapon = {title: "Blightburn Weapon", jsx: <><h2 id="spell-blightburn_weapon-blightburn-weapon">Blightburn Weapon</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 4, arcanist 5, inquisitor 4, investigator 4, magus 4, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one weapon<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You transform the target weapon into pure blightburn. The weapon functions as normal, but any creature that touches it, or that it strikes, takes 2d6 points of fire damage each round it remains in contact. In addition, the weapon emanates an aura of radiation that causes <Link to="/disease/blightburn_sickness">blightburn sickness</Link>. This is as the disease, but with a 10-foot radius and a save DC equal to this spell's save DC.</p>
</>};
const _blinding_ray = {title: "Blinding Ray", jsx: <><h2 id="spell-blinding_ray-blinding-ray">Blinding Ray</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 101</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/good">good</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> cleric 2, inquisitor 3, oracle 2, paladin 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one or more rays of light<br/><strong>Duration</strong> instantaneous (see text)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/race/dhampir">Dhampirs</Link> have access to the following spell.</em></p>
</blockquote>
<p>You blast your enemies with blinding rays of sunlight. You may fire one ray, plus one additional ray for every four levels beyond 3rd (to a maximum of three rays at 11th level). Each ray requires a ranged touch attack to hit. If a ray hits, it explodes into powerful motes of light, and the target must save or be blinded for 1 round. If the target has light blindness, light sensitivity, or is otherwise vulnerable to bright light, it instead must save or be blinded for 1d4 rounds and take 1d4 points of damage per two caster levels (maximum 5d4). Any creature blinded by a ray sheds light as a sunrod for the duration of its blindness. The rays may be fired at the same or different targets, but all rays must be aimed at targets within 30 feet of each other and fired simultaneously.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-blinding_ray--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Blinding Ray</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 86</Link><br/>On a successful saving throw, the target is dazzled for 1 round. On a failed saving throw, the target is instead blinded for 1d4 rounds.</p>
<p>A target with light blindness, light sensitivity, or any other vulnerability to light is instead blinded for 1d4 rounds on a successful saving throw and permanently blinded on a failed saving throw.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _blindness_deafness = {title: "Blindness/Deafness", jsx: <><h2 id="spell-blindness_deafness-blindnessdeafness">Blindness/Deafness</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 250</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> antipaladin 2, arcanist 2, bloodrager 2, bard 2, cleric 3, mesmerist 2, oracle 3, psychic 2, shaman 3, skald 2, sorcerer 2, spiritualist 3, warpriest 3, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> permanent (D)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You call upon the powers of unlife to render the subject blinded or deafened, as you choose.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-blindness_deafness--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Blindness/Deafness</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 86</Link><br/>You can cause the target to be both blinded and deafened at the same time. The target must attempt a saving throw against each effect separately.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _blink = {title: "Blink", jsx: <><h2 id="spell-blink-blink">Blink</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 250</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bard 3, magus 3, psychic 3, red mantis assassin 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)</p><p>You "blink" quickly back and forth between the Material Plane and the Ethereal Plane and look as though you're winking in and out of reality at random. Blink has several effects, as follows.</p>
<p>Physical attacks against you have a 50% miss chance, and the <Link to="/feat/blind_fight">Blind-Fight</Link> feat doesn't help opponents, since you're ethereal and not merely invisible. If the attack is capable of striking ethereal creatures, the miss chance is only 20% (for concealment).</p>
<p>If the attacker can see invisible creatures, the miss chance is also only 20%. (For an attacker who can both see and strike ethereal creatures, there is no miss chance.) Likewise, your own attacks have a 20% miss chance, since you sometimes go ethereal just as you are about to strike.</p>
<p>Any individually targeted spell has a 50% chance to fail against you while you're blinking unless your attacker can target invisible, ethereal creatures. Your own spells have a 20% chance to activate just as you go ethereal, in which case they typically do not affect the Material Plane (but they might affect targets on the Ethereal Plane).</p>
<p>While blinking, you take only half damage from area attacks (but full damage from those that extend onto the Ethereal Plane). Although you are only partially visible, you are not considered invisible and targets retain their Dexterity bonus to AC against your attacks. You do receive a +2 bonus on attack rolls made against enemies that cannot see invisible creatures.</p>
<p>You take only half damage from falling, since you fall only while you are material.</p>
<p>While blinking, you can step through (but not see through) solid objects. For each 5 feet of solid material you walk through, there is a 50% chance that you become material. If this occurs, you are shunted off to the nearest open space and take 1d6 points of damage per 5 feet so traveled.</p>
<p>Since you spend about half your time on the Ethereal Plane, you can see and even attack ethereal creatures. You interact with ethereal creatures roughly the same way you interact with material ones.</p>
<p>An ethereal creature is invisible, incorporeal, and capable of moving in any direction, even up or down. As an incorporeal creature, you can move through solid objects, including living creatures.</p>
<p>An ethereal creature can see and hear the Material Plane, but everything looks gray and insubstantial. Sight and hearing on the Material Plane are limited to 60 feet.</p>
<p>Force effects and abjurations affect you normally. Their effects extend onto the Ethereal Plane from the Material Plane, but not vice versa. An ethereal creature can't attack material creatures, and spells you cast while ethereal affect only other ethereal things. Certain material creatures or objects have attacks or effects that work on the Ethereal Plane. Treat other ethereal creatures and objects as material.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-blink--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Blink</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 86</Link><br/>You may spend a move action to remain corporeal or incorporeal until the end of your turn (you automatically resume blinking at the end of your turn).</p>
<p><em>Augmented (3rd):</em> If you expend two uses of mythic power, you can spend either a swift action or a move action to remain corporeal or incorporeal until the end of your turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _blistering_invective = {title: "Blistering Invective", jsx: <><h2 id="spell-blistering_invective-blistering-invective">Blistering Invective</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 224</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/language_dependent">language-dependent</Link>]; <strong>Level</strong> alchemist 2, bard 2, inquisitor 2, investigator 2, mesmerist 2, skald 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Area</strong> 30-ft. radius<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex partial, see text; <strong>Spell Resistance</strong> special, see below</p><p>You unleash an insulting tirade so vicious and spiteful that enemies who hear it are physically scorched by your fury. When you cast this spell, make an Intimidate check to demoralize each enemy within 30 feet of you. Enemies that are demoralized this way take 1d10 points of fire damage and must succeed at a Reflex save or catch fire. Spell resistance can negate the fire damage caused by this spell, but does not protect the creature from the demoralizing effect.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-blistering_invective--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Blistering Invective</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 86</Link><br/>Enemies that are demoralized by your Intimidate check take 2d8 points of fire damage and catch fire (no saving throw). Any Reflex save attempted to extinguish the flames automatically fails as long as the creature remains demoralized by your Intimidate check.</p>
<p><em>Augmented (5th):</em> If you expend two uses of mythic power, the spell doesn't have the language-dependent descriptor and you don't take a penalty on your Intimidate check to demoralize creatures that are larger than you.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _bloatbomb = {title: "Bloatbomb", jsx: <><h2 id="spell-bloatbomb-bloatbomb">Bloatbomb</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 175</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/acid">acid</Link>, <Link to="/spelldef/death">death</Link>]; <strong>Level</strong> antipaladin 4, arcanist 4, cleric 4, oracle 4, sorcerer 4, warpriest 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> living creature touched<br/><strong>Duration</strong> instantaneous and 1 minute/level (see text)<br/><strong>Saving Throw</strong> Fortitude negates or Reflex half (see text); <strong>Spell Resistance</strong> yes</p><p>The target creature dies if it fails a Fortitude saving throw and its Hit Dice are no more than half your caster level. If it dies, its corpse rapidly putrefies. The next creature to touch the corpse within 1 minute per level of the target's death causes the corpse to explode in a 10-foot-radius burst, dealing 3d6 points of acid damage (Reflex half).</p>
</>};
const _blood_armor = {title: "Blood Armor", jsx: <><h2 id="spell-blood_armor-blood-armor">Blood Armor</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 176</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 2, arcanist 2, bloodrager 2, investigator 2, psychic 2, red mantis assassin 2, sorcerer 2, summoner 2, unchained summoner 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>Your blood becomes as hard as iron upon contact with air. Each time you take at least 5 points of piercing or slashing damage, your armor gains a +1 enhancement bonus to your AC. An outfit of regular clothing counts as armor that grants no AC bonus for the purpose of this spell. This enhancement bonus stacks with itself, but not with an existing enhancement bonus, to a maximum enhancement bonus of +5. This spell has no effect while underwater or in environments that lack air.</p>
</>};
const _blood_biography = {title: "Blood Biography", jsx: <><h2 id="spell-blood_biography-blood-biography">Blood Biography</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 3, bloodrager 3, bard 2, cleric 3, inquisitor 3, medium 2, occultist 2, oracle 3, psychic 3, skald 2, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S, M/DF (a scrap of parchment)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature's blood or one bloodstain<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> no</p><p>You learn the answers to a specific set of questions about a creature so long as you have access to at least one drop of its blood. You can cast this spell on the blood of the living or the dead, but living or undead creatures are entitled to a saving throw to resist the spell. You can cast the spell on dried or fresh blood. Once you cast the spell the answers to the following four questions appear on any flat surface you designate (a wall, a piece of paper, and so on).</p>
<ul>
<li>Who are you? (The name by which the creature is most commonly known)</li>
<li>What are you? (Gender, race, profession/role)</li>
<li>How was your blood shed? (Brief outline of the events that caused its wound, to the best of the victim's knowledge)</li>
<li>When was your blood shed?</li>
</ul>
<p>These answers always appear in a language you can read even if the creature cannot speak that or any language.</p>
</>};
const _blood_blaze = {title: "Blood Blaze", jsx: <><h2 id="spell-blood_blaze-blood-blaze">Blood Blaze</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 143</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> alchemist 2, antipaladin 1, arcanist 2, bloodrager 2, cleric 2, investigator 2, magus 2, oracle 2, psychic 2, red mantis assassin 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><blockquote>
<p><em><Link to="/race/orc">Orcs</Link> have access to the following spell.</em></p>
</blockquote>
<p>The target gains a 5-foot-radius aura that causes the blood of creatures in that area to ignite upon contact with air. Any creature (including the spell's target) within the aura that takes at least 5 points of piercing, slashing, or bleed damage from a single attack automatically creates a spray of burning blood. The spray strikes a creature in a randomly determined square adjacent to the injured creature. The spray deals 1d6 points of fire damage to any creature in that square, and 1 point of splash damage to all creatures within 5 feet of the spray's target, including the target of this spell. A creature can only create one spray of burning blood per round. Creatures that do not have blood (including oozes and most constructs and undead) do not create blood sprays when attacked.</p>
</>};
const _blood_boil = {title: "Blood Boil", jsx: <><h2 id="spell-blood_boil-blood-boil">Blood Boil</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 24</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 5, magus 5, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of mercury)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 3 rounds<br/><strong>Saving Throw</strong> Fortitude negates (see text); <strong>Spell Resistance</strong> yes</p><p>The temperature of the target creature's blood (or other similar body fluid) begins to rise over the next 3 rounds during the caster's turn. Each round starting with the first, the target creature attempts a new saving throw at the start of the caster's turn to resist that round's effect. A successful save does not end the spell effect, but does prevent that round's effect. On the round that this spell is cast, the target becomes fatigued. On the next round, as the blood temperature begins to rise, the target's capillaries burst, dealing 1d6 points of Constitution damage to the target. On the third and final round, the target's blood begins to boil; the spell deals 1d6 points of damage per caster level (to a maximum of 15d6), and - if the target is still alive - the target becomes exhausted rather than fatigued.</p>
</>};
const _blood_crow_strike = {title: "Blood Crow Strike", jsx: <><h2 id="spell-blood_crow_strike-blood-crow-strike">Blood Crow Strike</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> cleric 4, oracle 4, warpriest 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>Your unarmed strikes release blasts of energy in the form of bolts of fire or glowing red crows, which fly instantaneously to strike your target. You can make unarmed strike or flurry of blows attacks against the target as if it were in your threatened area; each successful attack deals damage as if you had hit it with your unarmed strike, except half the damage is fire and half is negative energy (this negative energy does not heal undead). For example, if you are a 14th-level monk, you can use a flurry of blows to attack five times, creating one energy crow for each successful attack against the target, and dealing 2d6 points of damage (plus appropriate unarmed strike modifiers) with each crow.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-blood_crow_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Blood Crow Strike</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>Unarmed strikes attempted with this spell are treated as if you had the <Link to="/feat/improved_critical">Improved Critical</Link> (unarmed strike) feat. Use your tier plus your monk level (if any) when determining your unarmed strike damage for this spell. Fire damage from this spell bypasses fire resistance.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _blood_in_the_water = {title: "Blood in the Water", jsx: <><h2 id="spell-blood_in_the_water-blood-in-the-water">Blood in the Water</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 189</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/emotion">emotion</Link>]; <strong>Level</strong> arcanist 2, cleric 2, mesmerist 2, oracle 2, psychic 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 20 ft.<br/><strong>Area</strong> 20-ft.-radius emanation centered on you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>As part of the casting of this spell, you must deal 1 point of piercing or slashing damage to yourself to release your blood. This causes you to take 1 point of bleed damage. While the spell is in effect, all sharks, feeders in the depths, and creatures with the blood frenzy ability in the area gain a +2 bonus to Strength and Constitution and take a -2 penalty to AC. This is treated as blood frenzy for the purposes of other feats and effects, and doesn't stack with the effects of actual blood frenzy. If you cease bleeding, the spell immediately ends.</p>
</>};
const _blood_mist = {title: "Blood Mist", jsx: <><h2 id="spell-blood_mist-blood-mist">Blood Mist</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 209</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> druid 8, shaman 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of dried red algae)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> 60-ft. radius<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (see text); <strong>Spell Resistance</strong> yes</p><p>This spell summons forth a misty cloud of rust-red toxic algae. Any creature within the mist is coated by it, turning the creature the same reddish color. All targets within the mist gain <Link to="/rule/concealment">concealment</Link>. Any creature within the mist must save or take 1d4 points of Wisdom damage and become enraged, attacking any creatures it detects nearby (as the "attack nearest creature" result of the confused condition). An enraged creature remains so as long as the spell is in effect. A creature only needs to save once each time it is within the mist (though leaving and returning requires another save).</p>
</>};
const _blood_money = {title: "Blood Money", jsx: <><h2 id="spell-blood_money-blood-money">Blood Money</h2>
<p><strong>Sources</strong> <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 418</Link>, <Link to="/source/pathfinder_5_sins_of_the_saviors">Pathfinder #5: Sins of the Saviors pg. 59</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, magus 1, red mantis assassin 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> 1 material component<br/><strong>Duration</strong> instantaneous</p><p>You cast blood money just before casting another spell. As part of this spell's casting, you must cut one of your hands, releasing a stream of blood that causes you to take 1d6 points of damage. When you cast another spell in that same round, your blood transforms into one material component of your choice required by that second spell. Even valuable components worth more than 1 gp can be created, but creating such material components requires an additional cost of 1 point of Strength damage, plus a further point of damage for every full 500 gp of the component's value (so a component worth 500 to 999 gp costs a total of 2 points, 1,000 to 1,500 costs 3, etc.). You cannot create magic items with blood money.</p>
<p>For example, a sorcerer with the spell stoneskin prepared could cast blood money to create the 250 gp worth of diamond dust required by that spell, taking 1d6 points of damage and 1 point of Strength damage in the process.</p>
<p>Material components created by blood money transform back into blood at the end of the round if they have not been used as a material component. Spellcasters who do not have blood cannot cast blood money, and those who are immune to Strength damage (such as undead spellcasters) cannot use blood money to create valuable material components.</p>
</>};
const _blood_of_the_martyr = {title: "Blood of the Martyr", jsx: <><h2 id="spell-blood_of_the_martyr-blood-of-the-martyr">Blood of the Martyr</h2>
<p><strong>Sources</strong> <Link to="/source/chronicle_of_the_righteous">Chronicle of the Righteous pg. 50</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 2, inquisitor 3, oracle 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You cause the target to bleed from every orifice, and her organs and blood become suffused with positive energy. If the subject fails her Fortitude save, she takes 1d6 points of bleed damage per 4 caster levels (to a maximum of 4d6 at 16th level) when you cast this spell. Any creature that takes a full-round action to sup the blood of the bleeding subject heals a number of hit points equal to twice as many as the subject lost that round due to the bleed effect. The subject must be willing or helpless to sup her blood, which provokes attacks of opportunity. Only one creature can be healed in this way per round. The subject can lick her own wounds in this way to regain half as many hit points as she lost that round. If the bleeding effect is stopped or the spell's duration ends, the subject's blood no longer heals those who drink it, though in the latter case the subject continues to bleed until the bleeding is stopped via magical healing or a successful DC 15 Heal check.</p>
</>};
const _blood_rage = {title: "Blood Rage", jsx: <><h2 id="spell-blood_rage-blood-rage">Blood Rage</h2>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> adept 3, arcanist 3, bard 2, cleric 3, oracle 3, skald 2, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of blood from each creature to be affected)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one willing living creature per 2 levels, no two of which may be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The targets of this spell become angrier as they fight, the pain of their wounds fueling their strength. An affected creature gains a cumulative +2 morale bonus to Strength and a cumulative -1 penalty to AC for every 5 points of damage it takes (maximum +10 Strength, -5 AC) for the duration of the spell. These bonuses last until the spell expires or the target falls unconscious.</p>
</>};
const _blood_salvation = {title: "Blood Salvation", jsx: <><h2 id="spell-blood_salvation-blood-salvation">Blood Salvation</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> bloodrager 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (d; see below)</p><p>While under the effect of this spell, you're immune to any damaging area spells you cast. You can dismiss this spell as an immediate action when you are caught within the area of someone else's damaging area spell; if you do, you're immune to that particular casting of that spell as well. If you have the blood casting class feature, you can cast this spell as a swift action instead of a standard action while you're in a bloodrage.</p>
</>};
const _blood_scent = {title: "Blood Scent", jsx: <><h2 id="spell-blood_scent-blood-scent">Blood Scent</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 143</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, antipaladin 2, arcanist 3, bloodrager 3, cleric 3, druid 3, hunter 2, inquisitor 3, investigator 3, oracle 3, psychic 3, ranger 2, red mantis assassin 3, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> one creature/2 levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><blockquote>
<p><em><Link to="/race/orc">Orcs</Link> have access to the following spell.</em></p>
</blockquote>
<p>You greatly magnify the target's ability to smell the presence of blood. The target is considered to have the <Link to="/umr/scent">scent</Link> universal monster ability, but only for purposes of detecting and pinpointing injured creatures (below full hit points). Creatures below half their full hit points or suffering bleed damage are considered strong scents for this ability.</p>
<p>Orcs and any creature under the effects of rage gain a +2 morale bonus on attack and damage rolls against creatures they can smell with this spell, or a +4 morale bonus if the target's blood counts as a strong scent.</p>
</>};
const _blood_sentinel = {title: "Blood Sentinel", jsx: <><h2 id="spell-blood_sentinel-blood-sentinel">Blood Sentinel</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 176</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, arcanist 3, investigator 3, red mantis assassin 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a life-sized animal sculpture of a familiar made of clay, cloth, stone, or wood, plus mandrake root worth 25 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one animal sculpture<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>After casting this spell, you pour a few drops of your blood and saliva into the mouth of the animal sculpture material component, temporarily giving it life. The animal is bonded to you as if it were a familiar, and it has the abilities of a familiar (use your caster level as your effective wizard level to determine its abilities), but it does not grant you the <Link to="/feat/alertness">Alertness</Link> feat or the special ability of its animal type. If your blood sentinel is slain, you take 2 points of Intelligence drain and the blood sentinel's body becomes a destroyed statue. This spell has no effect if you already have a familiar or another blood sentinel.</p>
</>};
const _blood_song = {title: "Blood Song", jsx: <><h2 id="spell-blood_song-blood-song">Blood Song</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> bard 4, skald 4<br/><strong>Casting Time</strong> 2 minutes<br/><strong>Components</strong> V, S, M (the caster's blood)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched; see text<br/><strong>Duration</strong> 1 day or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>, with the following exceptions: only bard spells of the conjuration (healing), enchantment, and transmutation schools can be transferred; the imbued spells last for 1 day; and the subject isn't beholden to any principles regarding the imbued spells' use.</p>
<p>As part of the casting, the caster must shed some of his blood (or an equivalent humor). If the caster isn't susceptible to bleed damage, regardless of the reason, he can't cast blood song. For each spell that is imbued using blood song, the caster loses 5 hit points, which can't be regained by any means until the spell ends or is discharged.</p>
</>};
const _blood_tentacles = {title: "Blood Tentacles", jsx: <><h2 id="spell-blood_tentacles-blood-tentacles">Blood Tentacles</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> antipaladin 4, arcanist 5, cleric 5, oracle 5, shaman 5, sorcerer 5, summoner 4, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a fresh handful of the caster's blood)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no</p><p>You smear a handful of your own blood across your chest, causing one writhing tentacle per caster level to burst forth. You can direct these tentacles to attack a single creature within 15 feet as a standard action, or one creature per 5 caster levels as a full-round action. Each tentacle has an attack bonus equal to your base attack bonus plus either your Constitution or Charisma bonus (whichever is higher). Each tentacle deals 2d6 points of damage, and a tentacle collapses into dried blood on a successful hit, granting you a number of temporary hit points equal to the damage dealt. You can't gain more temporary hit points than your maximum number of hit points. These temporary hit points disappear after 1 hour.</p>
</>};
const _blood_ties = {title: "Blood Ties", jsx: <><h2 id="spell-blood_ties-blood-ties">Blood Ties</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 110</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> antipaladin 4, cleric 5, druid 5, hunter 5, inquisitor 5, oracle 5, psychic 5, shaman 5, warpriest 5, witch 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a small length of crimson string)<br/><strong>Range</strong> unlimited (see text)<br/><strong>Target</strong> two living creatures<br/><strong>Duration</strong> 1 day/level (D)<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> no</p><p>One of the targets of this spell must be a hostage - a bound, pinned, or helpless creature within your reach (though the spell doesn't end if the hostage later moves beyond your reach). The second target must be a member of the first target's family. If neither creature successfully saves against the spell, the second target also takes any damage conferred to the hostage, provided both are still alive, to a maximum of 10 points of damage per caster level per day (damage beyond that necessary to kill the first target does not transfer). This transferred damage is typeless and ignores the second creature's damage reduction and resistances. If either target succeeds at the saving throw, you can never attempt to exploit the connection between these particular two creatures again. The connection between your targets weakens when the two are less familiar with one another. Each target gains a +2 bonus on its save if the two are distant relations or related by marriage. Each target takes a -2 penalty on its save if the two targets are parent and child or siblings.</p>
</>};
const _blood_transcription = {title: "Blood Transcription", jsx: <><h2 id="spell-blood_transcription-blood-transcription">Blood Transcription</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 209</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> alchemist 2, arcanist 2, investigator 2, magus 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one dead spellcaster<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>By consuming 1 pint of blood from a spellcaster killed within the last 24 hours, you can attempt to learn a spell that spellcaster knew. Select one spell available to the dead spellcaster (this must be a spell on your spell list); you gain the knowledge of this spell for 24 hours. During this time, you may write it down (or teach it to your familiar, if you are a witch) using the normal rules for copying a spell from another source. Once you have learned it, you may prepare the spell normally.</p>
</>};
const _bloodbath = {title: "Bloodbath", jsx: <><h2 id="spell-bloodbath-bloodbath">Bloodbath</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 110</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> antipaladin 1, arcanist 2, bloodrager 1, cleric 2, inquisitor 2, medium 1, oracle 2, psychic 2, sorcerer 2, spiritualist 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a ceremonial dagger)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> up to one living creature/level, no two of which can be more than 30 feet apart<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You cut yourself with the dagger, dealing yourself 1d6 points of bleed damage. So long as you keep taking this bleed damage, your targets each bleed for 1d6 points of damage at the beginning of their turns. The bleed damage on any target ends if that target receives magical healing, or if your bleed damage ends for any reason. This spell has no effect if you're immune to bleed damage or can otherwise reduce or ignore the bleed damage to yourself.</p>
</>};
const _bloodhound = {title: "Bloodhound", jsx: <><h2 id="spell-bloodhound-bloodhound">Bloodhound</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, hunter 2, inquisitor 2, investigator 3, occultist 3, ranger 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of blood and a pinch of cinnamon)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level</p><p>You gain the scent special quality, including the ability to track by scent. You receive a +8 competence bonus on Perception checks involving smell and a +4 competence bonus on Survival checks to track using scent. You take a -4 penalty on saving throws against odor-related effects such as the stench ability and stinking cloud. A creature under the effects of bloodhound can detect poison by scent with a DC 20 Perception check.</p>
</>};
const _bloodstone_mirror = {title: "Bloodstone Mirror", jsx: <><h2 id="spell-bloodstone_mirror-bloodstone-mirror">Bloodstone Mirror</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_140_eulogy_for_roslars_coffer">Pathfinder #140: Eulogy for Roslar's Coffer pg. 72</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 7, occultist 5, oracle 7, witch 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a red bloodstone worth 500 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level</p><p>Developed due to <Link to="/faith/arazni">Arazni's</Link> fear that her stolen organs might be used to control her, this spell reflects any attempts to steal your free will. Whenever you are exposed to a mind-affecting effect or a spell that would otherwise give another creature control of your actions (such as <Link to="/spell/control_undead">control undead</Link>), you can dispel this effect as an immediate action to redirect the spell to a creature within 30 feet. The affected creature must attempt a save against the original DC of the triggering effect. On a failure, it is subject to the effects of the triggering spell, with the exception that you are treated as the original caster (statistics determined by caster level are still calculated according to its original caster). The target creature applies any spell resistance or immunities it has normally. You can have only one instance of this spell active at a time.</p>
</>};
const _bloodsworn_retribution = {title: "Bloodsworn Retribution", jsx: <><h2 id="spell-bloodsworn_retribution-bloodsworn-retribution">Bloodsworn Retribution</h2>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion pg. 22</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 6, hunter 4, oracle 6, paladin 4, ranger 4, warpriest 6<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (your blood)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> special (see text)</p><blockquote>
<p><em>In order to prepare this spell, the caster must spend an hour performing a ritual in which he beseeches <Link to="/faith/torag">Torag</Link> (or a member of his family) for the aid of <Link to="/faith/dranngvit">Dranngvit</Link>. For 24 hours after the ritual, the caster may prepare spells of the requested deity. The caster may only attune himself to one additional deity at a time.</em></p>
</blockquote>
<p>When you cast this spell, you cut yourself and swear an oath of retribution on your own blood. You decide how much damage you want to take from this attack, up to 25 points. This damage cannot be healed for as long as the spell is in effect. Anytime you perform an attack, save, or check that is directly related to the oath and brings you closer to the fulfillment of that oath, you gain a morale bonus to that roll equal to the number of hit points of damage you took from the oath divided by 5. The GM is the final arbiter over whether or not an action qualifies for this bonus. When you fulfill the oath (or choose to forsake it), the spell ends, and the lost hit points can be healed as normal.</p>
<p>For example, a notorious bandit leader killed Stigur's brother, and Stigur wants to avenge his brother's death. Stigur casts this spell and sacrifices 20 hit points. Thereafter Stigur gains a +4 morale bonus on attack rolls against the bandit leader's minions, saves against spells from said minions, Intimidate checks to coerce an informant to tell him where the bandit leader is camped, and so on.</p>
</>};
const _bloody_arrows = {title: "Bloody Arrows", jsx: <><h2 id="spell-bloody_arrows-bloody-arrows">Bloody Arrows</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> antipaladin 3, arcanist 4, hunter 3, inquisitor 3, magus 3, ranger 3, shaman 4, sorcerer 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one willing creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong>  (harmless); <strong>Spell Resistance</strong> no (harmless)</p><p>Whenever this spell's target hits a creature with a ranged weapon that successfully deals piercing or slashing damage, the struck creature takes 1 point of bleed damage. Unlike most bleed damage, the bleed damage dealt by the subject of this spell is cumulative up to an amount equal to 1/2 your caster level (to a maximum of 5 points of bleed damage at 10th level).</p>
</>};
const _bloody_claws = {title: "Bloody Claws", jsx: <><h2 id="spell-bloody_claws-bloody-claws">Bloody Claws</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> druid 4, hunter 3, ranger 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> living creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You give a creature the ability to deal bleed damage when making natural attacks so long as the attack deals slashing or piercing damage. This bleed damage for each attack is equal to one-half your caster level (limited to the creature's maximum damage with that attack), though bleed damage does not stack. When two or more attacks deal bleed damage, take the worse effect.</p>
</>};
const _bloody_tears_and_jagged_smile = {title: "Bloody Tears and Jagged Smile", jsx: <><h2 id="spell-bloody_tears_and_jagged_smile-bloody-tears-and-jagged-smile">Bloody Tears and Jagged Smile</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_71_rasputin_must_die">Pathfinder #71: Rasputin Must Die! pg. 75</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 2, cleric 2, oracle 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal and see text<br/><strong>Target</strong> you and see text<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/faith/szuriel">Szuriel's</Link> priests have access to the following spell.</em></p>
</blockquote>
<p>Your eyes turn black and weep blood, and your teeth become jagged fangs. You gain a bite attack (1d3 points of damage if you are Small, 1d4 points of damage if you are Medium). You gain a +4 profane bonus on Intimidate checks and on your spell DCs for spells with the fear descriptor. You perceive creatures as if using <Link to="/spell/deathwatch">deathwatch</Link>.</p>
</>};
const _blot = {title: "Blot", jsx: <><h2 id="spell-blot-blot">Blot</h2>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bard 3, cleric 3, oracle 3, red mantis assassin 3, skald 3, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a bit of cloth made wet with saliva)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 10 ft.-radius burst<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell reduces all types of writing and other recognizable symbols found on any sort of surface within range into illegible smears. It affects books, carvings on stone, or even tattoos with equal ease. It does not affect writing that is not actually on a surface, such as an illusion, projection, reflection, or anything similar. Spellbooks and magical items that contain writing (such as scrolls) gain a saving throw to resist the effects of this spell. Against magical writing created by spell effects (such as <Link to="/spell/glyph_of_warding">glyphs of warding</Link> or <Link to="/spell/symbol_of_death">symbols</Link>), blot instead functions as a <Link to="/spell/dispel_magic">dispel magic</Link> spell capable of targeting all such spell effects in the area. This spell has no effect on writing found on artifacts or similarly unique surfaces.</p>
</>};
const _blur = {title: "Blur", jsx: <><h2 id="spell-blur-blur">Blur</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> alchemist 2, arcanist 2, bard 2, investigator 2, magus 2, medium 2, mesmerist 2, occultist 2, psychic 2, red mantis assassin 2, skald 2, sorcerer 2, spiritualist 2, summoner 2, unchained summoner 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject's outline appears blurred, shifting, and wavering. This distortion grants the subject concealment (20% miss chance).</p>
<p>A see invisibility spell does not counteract the blur effect, but a true seeing spell does.</p>
<p>Opponents that cannot see the subject ignore the spell's effect (though fighting an unseen opponent carries penalties of its own).</p>
</>};
const _blurred_movement = {title: "Blurred Movement", jsx: <><h2 id="spell-blurred_movement-blurred-movement">Blurred Movement</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 176</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> alchemist 1, arcanist 1, bloodrager 1, bard 1, investigator 1, magus 1, mesmerist 1, occultist 1, psychic 1, red mantis assassin 1, skald 1, sorcerer 1, summoner 1, unchained summoner 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (D)</p><p>This spell functions as <Link to="/spell/blur">blur</Link>, except that the blurring occurs only when you move at least 10 feet on your turn and ceases at the end of your movement. It is therefore mainly used to thwart attacks on your turn, such as attacks of opportunity. If you move at least twice your speed on your turn, the blurring lasts until the start of your next turn.</p>
</>};
const _body_capacitance = {title: "Body Capacitance", jsx: <><h2 id="spell-body_capacitance-body-capacitance">Body Capacitance</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 176</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> alchemist 1, arcanist 1, investigator 1, red mantis assassin 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (an iron coil)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level or until discharged (see text)</p><p>If you take electricity damage while this spell is active, some of the energy is stored on your skin, as with holding the charge on a touch spell. You can release this stored electricity by making a melee touch attack. You gain a +3 bonus on the attack roll if your opponent is wearing metal armor, is carrying a metal weapon, or is made of metal. The target of your touch attack is dealt electricity damage equal to half the amount of electricity damage you took after you cast this spell (for example, if you saved for half damage against a lightning bolt and took only 15 points of electricity damage, your next touch attack deals 7 points of electricity damage). This spell is discharged once you hit with a melee touch attack to deliver its damage. If you take electricity damage multiple times while this spell is active, use the largest amount of electricity damage you took to determine your touch attack damage.</p>
</>};
const _body_double = {title: "Body Double", jsx: <><h2 id="spell-body_double-body-double">Body Double</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 2, bloodrager 2, bard 2, magus 2, skald 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (two glass beads)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> two creatures; see text<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>Upon casting this spell, choose a primary target and a secondary target, both of which must be within range. If the primary target fails or forfeits its saving throw, its appearance, scent, sounds, and mannerisms change to match those of the secondary target.</p>
<p>As long as the two targets are of the same size category, they are indistinguishable. As a consequence, if the targets are adjacent and a creature takes an action that would affect one of the targets (such as an attack, a targeted spell, or an area effect), that action has a 50% chance of affecting the other target instead.</p>
<p>Any action that would affect both of the creatures affects them both normally.</p>
<p>This spell does not deceive creatures that have true seeing. Likewise, a creature that can't perceive one of the targets is not fooled by this spell (even if the spell fooled that creature earlier), and its attacks, targeted spells, and other actions affect targets as normal.</p>
</>};
const _boiling_blood = {title: "Boiling Blood", jsx: <><h2 id="spell-boiling_blood-boiling-blood">Boiling Blood</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 209</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bloodrager 2, bard 2, cleric 2, oracle 2, psychic 2, red mantis assassin 2, skald 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> one creature per three levels, no two of which may be more than 30 ft. apart<br/><strong>Duration</strong> concentration+ 1 round/level (D)<br/><strong>Saving Throw</strong> Fortitude negates (see text); <strong>Spell Resistance</strong> yes</p><p>The blood of the targeted creatures begins to boil. If a target fails its save, it takes 1 point of fire damage per round. This spell has no effect on creatures that don't have blood.</p>
<p>If a target has the orc subtype, it doesn't take fire damage and instead gains a +2 morale bonus to Strength.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-boiling_blood--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Boiling Blood</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>A target that fails its save takes 1d3 points of fire damage per round. If a target has the orc subtype, it also gains fire resistance 5.</p>
<p><em>Augmented:</em> If you expend two uses of mythic power, you can affect allies as though they had the orc subtype.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _bombers_eye = {title: "Bomber's Eye", jsx: <><h2 id="spell-bombers_eye-bombers-eye">Bomber's Eye</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 1, investigator 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>This extract allows you to throw weapons farther and more accurately. While this extract is in effect, increase the range of any thrown weapon by 10 feet. In addition, you receive a +1 insight bonus on attack rolls made with thrown weapons.</p>
</>};
const _bone_fists = {title: "Bone Fists", jsx: <><h2 id="spell-bone_fists-bone-fists">Bone Fists</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 5</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 2, bloodrager 2, cleric 2, druid 2, hunter 2, oracle 2, psychic 2, shaman 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (the knucklebone of a dire animal)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> 1 creature/level, no two of which can be more than 30 feet apart<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong>  (harmless); <strong>Spell Resistance</strong> no</p><p>The bones of your targets' joints grow thick and sharp, protruding painfully through the skin at the knuckles, elbows, shoulders, spine, and knees. The targets each gain a +1 bonus to natural armor and a +2 bonus on damage rolls with natural weapons, and they are treated as having armor spikes, with which they are proficient.</p>
</>};
const _bone_flense = {title: "Bone Flense", jsx: <><h2 id="spell-bone_flense-bone-flense">Bone Flense</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 160</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bloodrager 2, cleric 3, druid 3, hunter 3, inquisitor 3, magus 3, oracle 3, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> M/F (a jagged shard of bone from a humanoid creature)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> no</p><p>Choose a creature that you can see. When that creature is struck by a weapon wielded by a member of the <Link to="/rule/red_mantis">Red Mantis</Link>, a sawtooth sabre, or by the claw of a giant mantis, the bone nearest to the wound instantly sprouts jagged, razor-sharp spurs that flense the muscle and flesh from the inside out unless the target succeeds at a Fortitude save. The creature takes 1d6 points of piercing damage per caster level. While the bone returns to normal immediately after dealing damage, the creature takes 1d4 points of bleed damage for 1 round per 2 caster levels. The victim is sickened by the pain for the duration of the bleeding. If the target creature has no bones, this spell has no effect.</p>
</>};
const _boneshaker = {title: "Boneshaker", jsx: <><h2 id="spell-boneshaker-boneshaker">Boneshaker</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 110</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> antipaladin 1, arcanist 2, cleric 2, inquisitor 2, oracle 2, sorcerer 2, spiritualist 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a human-shaped fetish made of bone)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one living creature or undead creature with a skeleton<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates or partial (see text); <strong>Spell Resistance</strong> yes</p><p>By using a bone fetish like a marionette, you take control of a target creature's skeleton. This has a variety of effects depending on whether the target is living or undead.</p>
<p>A living creature has its skeleton rattle within its flesh, causing it grievous harm. The target takes 3d6 points of damage, plus 1d6 additional points of damage per 2 caster levels you have. In addition, you can move the target 5 feet. This movement doesn't provoke attacks of opportunity. A successful saving throw halves the damage and negates the movement.</p>
<p>An undead creature takes no damage. Instead, you manipulate the undead, forcing it to take an immediate action to either move up to its speed (provoking attacks of opportunity as normal) or make a single attack against a creature of your choice in its reach. Either of these is the most basic version of the action the creature can take (it doesn't activate any special abilities that it could apply to the movement or attack, such as grab). A successful saving throw negates this effect. A mindless undead creature doesn't receive a save against this effect.</p>
</>};
const _boneshatter = {title: "Boneshatter", jsx: <><h2 id="spell-boneshatter-boneshatter">Boneshatter</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_84_pyramid_of_the_sky_pharaoh">Pathfinder #84: Pyramid of the Sky Pharaoh pg. 15</Link>, <Link to="/source/osirion_land_of_the_pharaohs">Osirion, Land of the Pharaohs pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 4, cleric 5, oracle 5, sorcerer 4, warpriest 5, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a broken bone)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one corporeal creature or object<br/><strong>Duration</strong> instantaneous and 1 minute/level (see text)<br/><strong>Saving Throw</strong> Fortitude partial (see text); <strong>Spell Resistance</strong> yes</p><p>The target's bones (or exoskeleton) splinter, dealing 1d6 points of damage per caster level (maximum 15d6) to the target, which is also exhausted for 1 minute per caster level from the pain and exertion of the transformation.</p>
<p>If the target succeeds at its save, it takes half damage and is fatigued rather than exhausted. Objects made of bone, chitin, or similar material take half again as much damage (+50%) from this spell. This spell has no effect on a creature that has neither a skeleton nor a hard carapace.</p>
</>};
const _book_ward = {title: "Book Ward", jsx: <><h2 id="spell-book_ward-book-ward">Book Ward</h2>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 2, bard 2, cleric 2, oracle 2, skald 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a drop of clear oil)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one touched object of up to 10 pounds/level<br/><strong>Duration</strong> 1 day/level or until discharged (see text)<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>As protection from energy, except as noted above and that the spell only protects against acid and fire damage. While the energy protection remains, the item is also completely waterproof (this protection extends to other liquids as well, such as alcohol and oil).</p>
</>};
const _borrow_corruption = {title: "Borrow Corruption", jsx: <><h2 id="spell-borrow_corruption-borrow-corruption">Borrow Corruption</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 111</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> antipaladin 2, cleric 4, druid 4, hunter 4, medium 2, occultist 3, oracle 4, psychic 4, ranger 4, shaman 4, warpriest 4, witch 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a dirty scrap of a good priest's raiment)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You touch a creature with at least one manifestation from a <Link to="/rule/corruption">corruption</Link>. You temporarily gain any stains and gifts that corruption grants to the creature, and the creature retains them. If the gifts have limited uses, you count as having no uses remaining. You take 1d3 points of Wisdom drain whenever you cast this spell.</p>
<p>If your campaign uses <Link to="/rule/sanity">the sanity system</Link>, your sanity score decreases by 2 (and thus your sanity edge decreases by 1) each time you cast this spell, instead of you taking Wisdom drain. Only <Link to="/spell/greater_restoration">greater restoration</Link>, <Link to="/spell/miracle">miracle</Link>, or <Link to="/spell/wish">wish</Link> can remove this decrease. A single casting of greater restoration removes one decrease of sanity from casting <Link to="/spell/borrow_corruption">borrow corruption</Link>, while a casting of miracle or wish removes them all.</p>
</>};
const _borrow_fortune = {title: "Borrow Fortune", jsx: <><h2 id="spell-borrow_fortune-borrow-fortune">Borrow Fortune</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> medium 3, oracle 3, psychic 3<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous; see text</p><p>When you make a d20 roll, you may choose to immediately cast this spell to reroll that die before success or failure is known, keeping the more favorable result. For the next two rounds following your casting of the spell, you must roll two dice each time a d20 roll is called for, keeping the less favorable result.</p>
</>};
const _borrow_skill = {title: "Borrow Skill", jsx: <><h2 id="spell-borrow_skill-borrow-skill">Borrow Skill</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> bard 1, medium 1, psychic 1, skald 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> up to 1 round/level (see description)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You borrow one of the target's known skills. After touching the subject, you can make a single check with the chosen skill using the subject's skill ranks, but modified by your own key ability. If you take longer than the spell's duration to make the check or the check requires more time, then it fails and you must use your own skill ranks (if any). If the borrowed skill is a class skill for you, you gain the +3 bonus on checks using that skill.</p>
</>};
const _borrowed_time = {title: "Borrowed Time", jsx: <><h2 id="spell-borrowed_time-borrowed-time">Borrowed Time</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 6, arcanist 6, bard 6, investigator 6, magus 6, skald 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)</p><p>A creation of the archmage Nex, this spell allows you to reach ahead in time and draw alacrity from the future at the expense of your own health. For the duration of this spell, you gain an extra swift action you can use only during your turn. You can't use this swift action to take a second immediate action between turns, but you can use it to take a swift action the turn after you've taken an immediate action. Each time you take an extra swift action in this fashion you take 1 point of Constitution damage. If you're immune to ability damage, you take 5 points of hit point damage instead. When the spell ends, you are staggered for 1d4+1 rounds from the temporal backlash.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-borrowed_time--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Borrowed Time</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 14</Link><br/>If you expend one use of mythic power, instead of taking an extra swift action, you can take either an extra move or an extra swift action each round. You can use this extra swift action to take two immediate actions between your turns; this consumes your extra swift action in your next round. Each extra action you take still deals damage to you as described above.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _bouncing_bomb_admixture = {title: "Bouncing Bomb Admixture", jsx: <><h2 id="spell-bouncing_bomb_admixture-bouncing-bomb-admixture">Bouncing Bomb Admixture</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 10</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, investigator 3<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no</p><p>Upon drinking an extract created with this formula, you make a significant change to your magical reserve that modifies the nature of the next bomb you create and throw during this extract's duration. This effect on your magical reserve has no effect on any discoveries that you use to modify your bombs, but you can only have one admixture effect (a formula with "bomb admixture" in its title) active at a time. If you drink another bomb admixture, the effects of the former bomb admixture end and the new one becomes active.</p>
<p>When you throw your next bomb, choose one target that would normally be hit by the bomb's splash damage. The target is affected as if it suffered a direct hit from the bomb instead.</p>
</>};
const _bouncy_body = {title: "Bouncy Body", jsx: <><h2 id="spell-bouncy_body-bouncy-body">Bouncy Body</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 105</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bloodrager 1, investigator 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level</p><p>The target's flesh becomes flexible and rubbery. It gains a +2 circumstance bonus on grapple combat maneuver checks and Escape Artist checks, as well as to its CMD against combat maneuver checks to grapple. Anytime the target would take falling damage, it treats falls as 20 feet shorter (minimum 0) for the purpose of determining damage. In addition, if the target falls against a hard surface, it can attempt an Acrobatics check (DC = the distance fallen) to attempt to bounce upward; success means the creature bounces upward half the distance fallen.</p>
</>};
const _bountiful_banquet = {title: "Bountiful Banquet", jsx: <><h2 id="spell-bountiful_banquet-bountiful-banquet">Bountiful Banquet</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 205</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> bard 4, cleric 4, druid 4, hunter 4, oracle 4, shaman 4, skald 4, warpriest 4<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (a turkey bone)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> feast for two creatures/level<br/><strong>Duration</strong> 1 hour; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You conjure a beautiful and delicious feast with hors d-oeuvres, four courses worth of food, and plentiful drink. The food appears on ornate serving trays or in exquisite covered tureens, as appropriate to each type of dish. Place settings and serving utensils also appear-enough for each creature that will participate in the feast-along with elegant tablecloths and table linens. The spell doesn't create furniture, but the feast does adapt to appear on top of existing tables (or similar objects in the environment).</p>
<p>Though the feast and all the finery last only 1 hour, creatures that partake remain nourished and sated for 24 hours. Though you have little control over the fine details of the feast, you can specify what type of dish you want for each course and what sorts of beverages are provided. The feast automatically adjusts depending on the type of spellcaster you are. For instance, a druid casting this spell typically creates a spread of natural berries, whole roasted animals, and sweet (and possibly fermented) nectar for beverages, all on rough-hewn wooden plates with chopsticks instead of silverware and sizable leaves replacing napkins.</p>
</>};
const _bow_spirit = {title: "Bow Spirit", jsx: <><h2 id="spell-bow_spirit-bow-spirit">Bow Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> hunter 4, ranger 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>A bow spirit is a shapeless force that hovers about you, taking ammunition from your quiver and firing it. For as long as the bow spirit lasts, you can spend a swift action to direct the bow spirit to fire an arrow or a bolt at a target of your choice, as if the bow spirit were firing the necessary ranged weapon. The bow spirit uses your base attack bonus plus your Dexterity modifier, as well as any bonuses and effects from feats you have that affect ranged attacks, or bonuses from the ammunition it uses. A bow spirit's attacks do not provoke attacks of opportunity. There must be ammunition available for the bow spirit to use, and it expends ammunition as if used by you.</p>
<p>A bow spirit occupies your space, and moves with you. It cannot be attacked or harmed by physical attacks, but <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link>, or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> affects it. A bow spirit's AC against touch attacks is 10 + your Dexterity modifier.</p>
</>};
const _bowstaff = {title: "Bowstaff", jsx: <><h2 id="spell-bowstaff-bowstaff">Bowstaff</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 224</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> hunter 1, inquisitor 1, occultist 2, paladin 1, ranger 1<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> one weapon (bow)<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>The bow that is touched takes on the rigidity and toughness of forged steel, allowing it to be used as a melee weapon. The spell allows a shortbow to be used as a club or a longbow to be used as a quarterstaff, although the bow retains its normal hit points and hardness. The bow's enhancement bonus, if any, applies on melee attack and damage rolls. Additional weapon special weapon qualities also apply to melee attacks if such qualities can be added to a melee weapon.</p>
</>};
const _brand = {title: "Brand", jsx: <><h2 id="spell-brand-brand">Brand</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> inquisitor 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>Brand etches an indelible rune or mark of no more than 6 characters onto a creature, inflicting 1 point of damage. The mark may be placed on any exposed portion of the creature, typically the head or forearm. A brand can be hidden by clothing or removed by scraping it away (causing 1d6 points of damage), though the brand returns if the damage is healed.</p>
<h3 id="spell-brand-greater-brand">Greater Brand</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> inquisitor 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like brand, except that it inflicts 1d6 points of damage when applied and cannot be removed, even temporarily. In addition, a greater brand blazes as bright as a torch when brought within 30 feet of a visible symbol of your faith. While the symbol is blazing, the recipient is sickened. Like the effects of bestow curse, a greater brand cannot be dispelled, but it can be removed by any means that removes a <Link to="/spell/mark_of_justice">mark of justice</Link>.</p>
</>};
const _brand_of_conformity = {title: "Brand of Conformity", jsx: <><h2 id="spell-brand_of_conformity-brand-of-conformity">Brand of Conformity</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 97</Link>, <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> inquisitor 1<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell etches the symbol of a nation, organization, or order on the target, dealing 1 point of damage. The mark can be placed on any exposed portion of the creature, typically the head or forearm. While branded in this way, the recipient loses the ability to speak or understand its racial language and the language of its homeland or primary culture (if these are different). For example, an elf raised among the Shoanti would lose Elven and Shoanti (if she knew both those <Link to="/misc/languages">languages</Link>), while a halfling raised among dwarves would lose both Halfling and Dwarven (if she knew both those languages). A gnome raised among gnomes would lose Gnome, but no other language. This spell never suppresses Common or Undercommon, nor does it prevent spellcasting, though it may prevent a target from speaking intelligibly if it suppresses all of the target's languages. A brand of conformity can be hidden beneath clothing or removed by scraping it away (the latter deals 1d6 points of damage, though the brand returns if that damage is healed). In any event, the language-suppression element of a brand of conformity continues to function even when hidden or scraped away.</p>
</>};
const _brand_of_hobbling = {title: "Brand of Hobbling", jsx: <><h2 id="spell-brand_of_hobbling-brand-of-hobbling">Brand of Hobbling</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 98</Link>, <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> inquisitor 2<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell etches a symbol of chains, a particular prison, or a lawful institution on the target, dealing 1d6 points of damage. The mark can be placed on any exposed portion of the creature, typically on the head or forearm. While the recipient is branded in this way, all of its movement speeds are reduced by half (rounded down to the next 5-foot increment). A brand of hobbling can be hidden by clothing or removed by scraping the brand away (the latter deals 1d6 points of damage, though the brand returns if that damage is healed), but in either case the effects of a brand of hobbling continue to function.</p>
</>};
const _brand_of_tracking = {title: "Brand of Tracking", jsx: <><h2 id="spell-brand_of_tracking-brand-of-tracking">Brand of Tracking</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 98</Link>, <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> inquisitor 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell etches the symbol of an eye or a lawful institution on the target, dealing 1d6 points of damage. The mark can be placed on any exposed portion of the creature, typically the head or forearm. While the target is branded in this way, twice per day as a standard action, you can instantly determine in what direction and how far away the target is, as long as it is within a range equal to 1 mile per your caster level. If the target travels beyond this range or to another plane, you cannot gain information about the recipient's location. Similarly, if the target becomes warded by a spell or effect that thwarts divination spells (such as nondetection) or moves into such an area (such as one created by antimagic field), you cannot gain information about the target's location. This effect otherwise works as a locate creature spell that lasts for 1 minute per caster level. It can be fooled by mislead but not by polymorph.</p>
<p>A brand of tracking can be hidden by clothing or temporarily removed by scraping it away (the latter deals 1d6 points of damage, though the brand returns if that damage is healed, or 1 day later otherwise). The effects of a brand of tracking continue to function even when hidden or scraped away. A brand of tracking cannot be dispelled, but it can be permanently removed by any means that removes a <Link to="/spell/mark_of_justice">mark of justice</Link>.</p>
</>};
const _break = {hasJL:true,title: "Break", jsx: <><div className="jumpList" id="spell-break-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-break-mythic_break">Mythic Break</InnerLink></li><li><InnerLink toTop to="spell-break-greater-break">Greater Break</InnerLink></li></ul></div><h2 id="spell-break-break">Break</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, bloodrager 1, occultist 1, psychic 1, red mantis assassin 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a twig)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one Medium or smaller object<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You can attempt to break or at least damage any one Medium or smaller object within range. If the target fails its Fortitude saving throw, it gains the broken condition. If cast on a broken item, that item is destroyed on a failed save.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-break--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-break-mythic_break" data-hash-target>Mythic Break</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link></p>
<p>You can target up to 1 Medium or smaller object per caster level.</p>
<p><em>Augmented (3rd):</em> If you expend two uses of mythic power, target objects gain the broken condition on a successful save and are destroyed on a failed save. This doesn't affect mythic objects or objects held or carried by mythic creatures.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-break-greater-break" data-hash-target>Greater Break</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 205</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 6, bloodrager 4, occultist 6, psychic 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (an unbroken platinum tuning fork worth 100 gp)<br/><strong>Range</strong> 30 ft.<br/><strong>Targets</strong> all Medium or smaller objects in a 30-ft. burst centered on you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes (object)</p><p>You release a burst of destructive energy. Each Medium or smaller object in the area gains the broken condition unless it succeeds at a Fortitude saving throw. If a broken object fails this save, it is instead destroyed. Magic items can be broken by this spell, but not destroyed. Objects in your possession are not immune.</p>
</>};
const _break_enchantment = {title: "Break Enchantment", jsx: <><h2 id="spell-break_enchantment-break-enchantment">Break Enchantment</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> adept 5, arcanist 5, bard 4, cleric 5, inquisitor 5, medium 4, mesmerist 4, occultist 4, oracle 5, paladin 4, psychic 4, shaman 5, skald 4, sorcerer 5, spiritualist 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> up to one creature per level, all within 30 ft. of each other<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> no</p><p>This spell frees victims from enchantments, transmutations, and curses. Break enchantment can reverse even an instantaneous effect. For each such effect, you make a caster level check (1d20 + caster level, maximum +15) against a DC of 11 + caster level of the effect. Success means that the creature is free of the spell, curse, or effect. For a cursed magic item, the DC is equal to the DC of the curse.</p>
<p>If the spell is one that cannot be dispelled by <Link to="/spell/dispel_magic">dispel magic</Link> or <Link to="/spell/stone_to_flesh">stone to flesh</Link>, break enchantment works only if that spell is 5th level or lower.</p>
<p>If the effect comes from a permanent magic item, break enchantment does not remove the curse from the item, but it does free the victim from the item's effects.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-break_enchantment--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Break Enchantment</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>Against non-mythic effects, the spell automatically succeeds without requiring a caster level check. Against mythic effects, add your tier to your caster level check. The maximum level of spell this spell can remove is 5 + half your tier.</p>
<p><em>Augmented (7th):</em> If you expend two uses of mythic power, you can apply a removed enchantment, transmutation, or curse to the creature that originally cast it. The creature must be a valid target of the spell and on the same plane as you, and it gets a saving throw at the effect's original DC.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _breath_of_life = {title: "Breath of Life", jsx: <><h2 id="spell-breath_of_life-breath-of-life">Breath of Life</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> cleric 5, oracle 5, shaman 5, spiritualist 5, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (harmless) or Will half, see text; <strong>Spell Resistance</strong> yes (harmless) or yes, see text</p><p>This spell cures 5d8 points of damage + 1 point per caster level (maximum +25).</p>
<p>Unlike other spells that heal damage, breath of life can bring recently slain creatures back to life. If cast upon a creature that has died within 1 round, apply the healing from this spell to the creature. If the healed creature's hit point total is at a negative amount less than its Constitution score, it comes back to life and stabilizes at its new hit point total. If the creature's hit point total is at a negative amount equal to or greater than its Constitution score, the creature remains dead. Creatures brought back to life through breath of life gain a temporary negative level that lasts for 1 day.</p>
<p>Creatures slain by death effects cannot be saved by breath of life.</p>
<p>Like <Link to="/main/cure_spells">cure spells</Link>, breath of life deals damage to undead creatures rather than curing them, and cannot bring them back to life.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-breath_of_life--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Breath of Life</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>The spell heals 5d12 points of damage + 1 point per caster level (maximum +25). It can revive a creature that died of hp damage within the past 2 rounds. If the target was slain by a death effect that allows a saving throw, this spell allows the creature to attempt another save against that effect. If this save is successful, the creature is revived with -10 hp plus the amount healed by this spell.</p>
<p><em>Augmented (9th):</em> If you expend two uses of mythic power, you can target up to one creature per caster level within 30 feet of you. Alternatively, you can target one creature that has been dead for a number of rounds up to your caster level.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _breeze = {title: "Breeze", jsx: <><h2 id="spell-breeze-breeze">Breeze</h2>
<p><strong>Sources</strong> <Link to="/source/paizo_blog___ultimate_cantrips">Paizo Blog - Ultimate Cantrips</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> arcanist 0, sorcerer 0, wizard 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a miniature fan)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature or object<br/><strong>Duration</strong> 1 hour (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>You create a light wind that blows against the target, from a direction of your choice. The breeze grants the subject a +2 bonus on saves against very hot conditions, severe heat, breath weapons, and saves against cloud vapors and gases (such as <Link to="/spell/cloudkill">cloudkill</Link>, <Link to="/spell/stinking_cloud">stinking cloud</Link>, and inhaled poisons). This spell does not function without air or underwater.</p>
<p>You can only have one breeze active at any one time. If you cast this spell while another casting is still in effect, the previous casting is dispelled.</p>
<p><strong>Note:</strong> This is a rare cantrip. Spellcasters that gain access to all 0-level spells at 1st level do not gain access to rare cantrips. A spellcaster gains access to rare cantrips only by uncovering their secrets in some other way. Some are guarded by jealous mages, while others are lost in missing libraries or molder on forgotten scrolls.</p>
</>};
const _brightest_night = {title: "Brightest Night", jsx: <><h2 id="spell-brightest_night-brightest-night">Brightest Night</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 15</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, bard 1, cleric 1, druid 1, hunter 1, oracle 1, paladin 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one willing creature plus one additional willing creature per 3 levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You grant low-light vision to the affected creatures. Creatures that already have low-light vision have their existing low-light vision enhanced so that they can see four times as far in conditions of dim light. Creatures within 10 feet of someone under the effects of brightest night do not gain concealment from dim light.</p>
</>};
const _brilliant_inspiration = {title: "Brilliant Inspiration", jsx: <><h2 id="spell-brilliant_inspiration-brilliant-inspiration">Brilliant Inspiration</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/language_dependent">language-dependent</Link>]; <strong>Level</strong> bard 6, psychic 8, skald 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 round/level and special (see below)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You open a link between your mind and the subject's mind, giving advice and encouragement for as long as the spell is in effect. Each time the subject of the spell makes an attack roll, ability check, or skill check, it rolls two d20s and takes the better result. If any roll is a natural 20, the spell's effect ends-your brilliant advice is spent.</p>
</>};
const _bristle = {title: "Bristle", jsx: <><h2 id="spell-bristle-bristle">Bristle</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 207</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 1, hunter 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes</p><p>You give a creature the ability to redirect a portion of its innate toughness away from its own defense and toward the amount of damage it deals with natural attacks. Each round, as a swift action at the start of its turn, the creature can choose to reduce some or all of its natural armor bonus to AC and gain an enhancement bonus on all damage rolls for natural attacks equal to that amount. The reduction to natural armor, and thus the enhancement bonus on damage rolls, cannot exceed 1 point per 3 caster levels, to a maximum penalty/bonus of -5/+5 at 15th level. A creature cannot reduce its natural armor bonus to less than 0 with this spell. All attacks directed against the creature use its adjusted AC until the start of its next turn, at which time it can choose to modify its AC again or keep it at its current level. Creatures make this decision without any need for conscious thought or reflection; even creatures with no Intelligence score can benefit from this spell, although they always opt for the maximum possible reduction and bonus, regardless of any tactical advantage they might lose.</p>
</>};
const _brittle_portal = {title: "Brittle Portal", jsx: <><h2 id="spell-brittle_portal-brittle-portal">Brittle Portal</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 230</Link>, <Link to="/source/faiths_of_corruption">Faiths of Corruption pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> antipaladin 2, arcanist 2, cleric 2, druid 2, hunter 2, inquisitor 2, oracle 2, red mantis assassin 2, sorcerer 2, warpriest 2, witch 2, wizard 2 (Rovagug; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 5-ft.-radius spread<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell weakens the bonds of existence, and reduces the hardness of any nonmagical surface within its area of effect by 2 per caster level. The spell is centered on a flat surface chosen by the caster, and the hardness reduction effect persists for the duration of the spell.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _brow_gasher = {title: "Brow Gasher", jsx: <><h2 id="spell-brow_gasher-brow-gasher">Brow Gasher</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 224</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 2, bloodrager 2, hunter 2, inquisitor 2, magus 2, occultist 2, ranger 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Area</strong> one slashing melee weapon touched<br/><strong>Duration</strong> 1 round/level or until discharged<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>You imbue a slashing melee weapon with the ability to deal a gruesome head wound. When the target weapon hits a living creature, in addition to the normal effects of that hit, the wielder can discharge this spell as a free action to open a gash on the target's forehead that deals bleed damage equal to half your caster level. At the start of each of the target's turns, when it takes bleed damage, it also takes a cumulative -1 penalty on all attack rolls. When that penalty reaches -3, the target also treats all targets as having concealment (20% miss chance). When the penalty reaches -5, the target is blinded. Stopping the bleed damage ends the effects this spell imposes on the bleeding creature. A target that is immune to bleed damage is also immune to all this spell's effects.</p>
</>};
const _build_trust = {title: "Build Trust", jsx: <><h2 id="spell-build_trust-build-trust">Build Trust</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 205</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> bard 2, cleric 2, inquisitor 2, mesmerist 2, oracle 2, paladin 1, psychic 2, skald 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a gold piece)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 day/level; see text<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You get a sense of the best way to interact with the target in order to encourage positive regard and fellowship toward you. You gain a +2 circumstance bonus on all Charisma checks and Charisma-based skill checks you attempt when interacting with the target. In addition, whenever you fail a Charisma check or Charisma-based skill check when interacting with the target, you can reroll the check as an immediate action. Attempting this reroll grants the target a new saving throw to end the spell. The target doesn't become hostile to you when the spell ends, but it does become disillusioned of its new trust in you. Attacking the target or taking an obvious hostile action against it automatically ends the spell.</p>
<p>If you are using the <Link to="/rule/contacts">contacts</Link> rules, your <Link to="/rule/trust">trust score</Link> with the target increases by 1 for the duration of the spell. If you're using the individual influence system, if the target fails its initial saving throw you learn one of its influence skills, strengths, or weaknesses as though you had succeeded at a discovery check.</p>
</>};
const _bullet_shield = {title: "Bullet Shield", jsx: <><h2 id="spell-bullet_shield-bullet-shield">Bullet Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 2, arcanist 2, bloodrager 2, investigator 2, occultist 2, psychic 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a bullet)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The warded creature gains a +4 deflection bonus to AC against firearm and ranged attacks, with an additional +1 to the bonus for every five caster levels you have (to a maximum of +8 at 20th level). Though the spell is called bullet shield, it also grants this protection from attacks made from firearms with the scatter weapon quality.</p>
</>};
const _bullet_ward = {title: "Bullet Ward", jsx: <><h2 id="spell-bullet_ward-bullet-ward">Bullet Ward</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 176</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> antipaladin 2, arcanist 2, bard 2, hunter 2, inquisitor 2, paladin 2, psychic 2, ranger 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (one to four adamantine bullets, each worth 61 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level or until discharged</p><p>You toss several adamantine bullets into the air, which then hover protectively nearby and intercept firearm attacks targeting you. The number of bullets protecting you is equal to half your caster level (maximum 4). When an opponent takes a shot at you with a firearm, as an immediate action you can designate a hovering bullet to attempt to block the attack, increasing your AC against that attack by 10. Doing this destroys the adamantine bullet whether or not the attack hits. The spell is discharged when all affected adamantine bullets are destroyed or taken from you. Each adamantine bullet has AC 24, 20 hit points, and hardness 20.</p>
</>};
const _bulls_strength = {title: "Bull's Strength", jsx: <><h2 id="spell-bulls_strength-bulls-strength">Bull's Strength</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> adept 2, alchemist 2, antipaladin 2, arcanist 2, bloodrager 2, cleric 2, druid 2, hunter 2, investigator 2, magus 2, medium 2, oracle 2, paladin 2, psychic 2, red mantis assassin 2, shaman 2, sorcerer 2, summoner 2, unchained summoner 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a few hairs, or a pinch of dung, from a bull)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject becomes stronger. The spell grants a +4 enhancement bonus to Strength, adding the usual benefits to melee attack rolls, melee damage rolls, and other uses of the Strength modifier.</p>
<h3 id="spell-bulls_strength-mass-bulls-strength">Mass Bull's Strength</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 6, cleric 6, druid 6, hunter 6, magus 6, oracle 6, psychic 6, shaman 6, sorcerer 6, summoner 4, unchained summoner 6, warpriest 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a few hairs, or a pinch of dung, from a bull)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like bull's strength, except that it affects multiple creatures.</p>
</>};
const _bungle = {title: "Bungle", jsx: <><h2 id="spell-bungle-bungle">Bungle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 209</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>); <strong>Level</strong> arcanist 1, mesmerist 1, psychic 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one humanoid<br/><strong>Duration</strong> concentration+ 2 rounds or until triggered<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>The target takes a -20 penalty on its next attack roll or check that requires a d20 roll. The action must be one deliberately taken by the target on its turn. Creatures with more than 10 HD are unaffected by this spell.</p>
</>};
const _buoyancy = {title: "Buoyancy", jsx: <><h2 id="spell-buoyancy-buoyancy">Buoyancy</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 177</Link>, <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bard 2, psychic 2, red mantis assassin 2, shaman 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one Medium or smaller object or creature/level, no two of which can be more than 20 ft. apart<br/><strong>Duration</strong> up to 1 round/level (see text)<br/><strong>Saving Throw</strong> Will negates (harmless) or Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>The affected targets become incredibly buoyant, floating naturally on any water at least 1 foot deep. An affected creature that deliberately tries to submerge must succeed at a DC 20 Swim check every round to stay underwater. If a target spends at least 1 round on dry land, the spell ends for that creature only.</p>
</>};
const _burdened_thoughts = {title: "Burdened Thoughts", jsx: <><h2 id="spell-burdened_thoughts-burdened-thoughts">Burdened Thoughts</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, druid 2, hunter 2, shaman 2, sorcerer 3, witch 2, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a lead bearing wrapped in clay)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You fill a creature's mind with the realization of its earthly weight and responsibilities. Disheartened and wearied by these thoughts, the creature gains heavy encumbrance and is unable to fly (if already flying, it must land as soon as possible). If the creature is three or more size categories larger than you, it's also staggered.</p>
</>};
const _burn_corruption = {title: "Burn Corruption", jsx: <><h2 id="spell-burn_corruption-burn-corruption">Burn Corruption</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 218</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/good">good</Link>]; <strong>Level</strong> arcanist 5, bloodrager 4, magus 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Area</strong> 10-ft. cube/level (S)<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em>The following spell is available to the indicated race or ethnicity: <Link to="/race/elf">Elf</Link></em></p>
</blockquote>
<p>This spell fills the area with violet flames that scour an area clean of life - especially of the corrupted life of the Abyss. Creatures (and foliage) in the area take 1d8 points of fire damage per 2 caster levels you possess (maximum 7d8) unless they are outsiders with the chaotic and evil subtypes or are otherwise tainted by demons, in which case they instead take 1d6 points of fire damage per caster level (maximum 15d6). This fire damage ignores the fire resistance granted by the demon subtype, but it does not penetrate any other form of fire resistance or immunity.</p>
</>};
const _burning_arc = {title: "Burning Arc", jsx: <><h2 id="spell-burning_arc-burning-arc">Burning Arc</h2>
<p><strong>Sources</strong> <Link to="/source/humans_of_golarion">Humans of Golarion pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one primary target plus one additional target/3 levels (each of which must be within 15 ft. of the primary target)<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>Keleshites brag that they stole this spell from genie-kind thousands of years ago while other civilizations struggled without fire.</p>
<p>This spell causes an arc of flame to leap from your fingers, burning a number of enemies nearby. It deals 1d6 points of fire damage per caster level (maximum 10d6). For every additional target the discharge arcs to, reduce the number of damage dice by half (rounded down). Therefore, at 9th level, your burning arc deals 9d6 points of fire damage to the primary target, then 4d6 points of fire damage to a secondary target, then 2d6 points of fire damage to an additional target.</p>
<p>Each target can attempt a Reflex saving throw for half damage. The Reflex DC to halve the damage of the secondary bolts is 2 lower than the DC to halve the damage of the primary bolt. You may choose secondary targets as you like, but they must all be within 15 feet of the primary target, and no target can be struck more than once. You can choose to affect fewer secondary targets than the maximum.</p>
</>};
const _burning_disarm = {title: "Burning Disarm", jsx: <><h2 id="spell-burning_disarm-burning-disarm">Burning Disarm</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 22</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 1, cleric 1, druid 1, hunter 1, oracle 1, red mantis assassin 1, sorcerer 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> held metal item of one creature or 15 lbs. of unattended metal<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex negates (object, see text); <strong>Spell Resistance</strong> yes (object)</p><p>This spell causes a metal object to instantly become red hot. A creature holding the item may attempt a Reflex save to drop it and take no damage (even if it is not their turn), otherwise the hot metal deals 1d4 points of fire damage per caster level (maximum 5d4). Circumstances that prevent the creature from dropping the item (such as a locked gauntlet) mean the creature gets no saving throw. The heat does not harm the item, and it does not get hot enough or last long enough to ignite flammable objects. The item cools to its previous temperature almost instantly. If cast underwater, burning disarm deals half damage and boils the surrounding water.</p>
</>};
const _burning_gaze = {title: "Burning Gaze", jsx: <><h2 id="spell-burning_gaze-burning-gaze">Burning Gaze</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 2, bloodrager 2, druid 2, hunter 2, magus 2, mesmerist 2, occultist 2, shaman 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (eye of a mundane salamander)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates (see text); <strong>Spell Resistance</strong> yes</p><p>Your eyes burn like hot coals, allowing you to set objects or foes alight with a glance.</p>
<p>As a standard action as long as this spell's effects persist, you may direct your burning gaze against a single creature or object within 30 feet of your location. Targeted creatures must succeed at a Fortitude save or take 1d6 points of fire damage. Unattended objects do not get a save. Creatures damaged by the spell must make a Reflex save or catch fire. Each round, burning creatures may attempt a Reflex save to quench the flames; failure results in another 1d6 points of fire damage. Flammable items worn by a creature must also save or take the same damage as the creature. If a creature or object is already on fire, it suffers no additional effects from burning gaze.</p>
<p>Note that this spell does not grant an actual gaze attack-foes and allies are not in danger of catching on fire simply by meeting your gaze.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-burning_gaze--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Burning Gaze</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>You may focus your burning gaze on a creature or object as a move action instead of as a standard action. The target takes 1d8 points of fire damage for failing its save and for each round it's on fire.</p>
<p><em>Augmented:</em> If you expend two uses of mythic power, once during the spell's duration you can, as a full-round action, direct your burning gaze at up to one creature per caster level.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _burning_hands = {title: "Burning Hands", jsx: <><h2 id="spell-burning_hands-burning-hands">Burning Hands</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> adept 1, arcanist 1, bloodrager 1, magus 1, occultist 1, shaman 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 15 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>A cone of searing flame shoots from your fingertips. Any creature in the area of the flames takes 1d4 points of fire damage per caster level (maximum 5d4). Flammable materials burn if the flames touch them. A character can extinguish burning items as a full-round action.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-burning_hands--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Burning Hands</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>The range increases to 20 feet, and the damage dealt increases to 1d6 points of fire damage per caster level (maximum 5d6).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _burning_sands = {title: "Burning Sands", jsx: <><h2 id="spell-burning_sands-burning-sands">Burning Sands</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 16</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/earth">earth</Link>, <Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 1, druid 1, hunter 1, ranger 1, shaman 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a handful of sand)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> 20-ft. radius<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You cause sheets of hot sand to spread over the ground in the area of effect. This layer of sand is 1 foot deep and constantly shifts and churns, transforming the ground in the area into difficult terrain. The sand itself burns, and periodic flames rise from the grit. While these flames cannot ignite objects, they deal 1d4 points of fire damage to any creature that ends its turn in contact with the ground within the area of effect. At the end of the duration, the sand vanishes, leaving no after-effects (other than damage dealt).</p>
</>};
const _burrow = {title: "Burrow", jsx: <><h2 id="spell-burrow-burrow">Burrow</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, arcanist 3, bloodrager 3, druid 3, hunter 3, investigator 3, ranger 3, red mantis assassin 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject can burrow at a speed of 15 feet (or 10 feet if it wears medium or heavy armor, or if it carries a medium or heavy load) through sand, loose soil, or gravel, or at a speed of 5 feet through stone. Using burrow requires only as much concentration as walking, so the subject can attack or cast spells normally. The burrowing creature cannot charge or run. Loose material collapses behind the target 1 round after it leaves the area. This spell does not give the target the ability to breathe underground, so when passing through loose material, the creature must hold its breath and take only short trips, or else it may suffocate.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-burrow--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Burrow</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>The target can breathe underground while burrowing. If you're 3rd tier, the burrow speed increases to 20 feet through sand, soil, or gravel, and to 10 feet through stone. At 6th tier, these speeds increase to 30 feet and 15 feet respectively. At 9th tier, these speeds increase to 40 feet and 20 feet.</p>
<p><em>Augmented (3rd):</em> If you expend two uses of mythic power, the burrowing creature may leave behind an open tunnel with a diameter equal to half its space. When the spell's effect ends, this tunnel closes up immediately.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _burst_bonds = {title: "Burst Bonds", jsx: <><h2 id="spell-burst_bonds-burst-bonds">Burst Bonds</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> inquisitor 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> touch<br/><strong>Target</strong> one object or creature restraining you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude half (object); <strong>Spell Resistance</strong> yes</p><p>You blast your restraints with divine wrath, dealing 1d6 points of damage per caster level to the target object (maximum 5d6), ignoring hardness of 10 or less. A Fortitude save halves the damage, although only magical restraints receive a saving throw.</p>
<p>You can also target a creature that is grappling or otherwise restraining you (such as by adhesive or the swallow whole ability) with the spell. You don't need to make a touch attack to use burst bonds against a creature, and you can cast this spell without making a concentration check while grappled or pinned. The creature does not take damage as above. If you are grappled and your target fails its save, you may make an immediate attempt to break the grapple (but not reverse it) as a free action, with a +1 luck bonus to your CMB per caster level (maximum +5). If the target creature fails its save and you are restrained by an ability that originally allowed a saving throw, burst bonds allows a new saving throw with a +1 luck bonus per two caster levels (maximum +5).</p>
</>};
const _burst_of_adrenaline = {title: "Burst of Adrenaline", jsx: <><h2 id="spell-burst_of_adrenaline-burst-of-adrenaline">Burst of Adrenaline</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 160</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> mesmerist 1, psychic 1, spiritualist 1<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You draw upon your body's inner reserves of strength, leaving you winded. When you are about to make a d20 roll based on Strength, Dexterity, or Constitution, you can cast this spell to gain a +8 enhancement bonus to Strength, Dexterity, or Constitution for that roll, but you are fatigued for 1 round afterward.</p>
</>};
const _burst_of_force = {title: "Burst of Force", jsx: <><h2 id="spell-burst_of_force-burst-of-force">Burst of Force</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 10</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> arcanist 5, psychic 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Area</strong> 20-ft.-radius burst centered on you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude half (see text); <strong>Spell Resistance</strong> yes</p><p>With a burst of telekinetic force, you deal 1d6 points of force damage per caster level (maximum 15d6 points of damage) to all other creatures in the affected area. A successful Fortitude save reduces the damage taken by half. A creature that fails its Fortitude save must also succeed at a Reflex save or be knocked prone.</p>
</>};
const _burst_of_glory = {title: "Burst of Glory", jsx: <><h2 id="spell-burst_of_glory-burst-of-glory">Burst of Glory</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 230</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 21</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> cleric 5, inquisitor 4, oracle 5, paladin 4, warpriest 5 (Iomedae; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 10 ft.<br/><strong>Area</strong> 10-ft.-radius burst, centered on you<br/><strong>Duration</strong> 1 round/level (d; see text)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Allies in the area of this spell at the time of casting gain a +1 sacred bonus on attack rolls and saves against fear effects, plus 1 temporary hit point per caster level (maximum 20). You shine with a white or golden radiance equal to a torch for the spell's duration, though you can dismiss the glow effect as a free action.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _burst_of_insight = {title: "Burst of Insight", jsx: <><h2 id="spell-burst_of_insight-burst-of-insight">Burst of Insight</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 160</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> medium 1, mesmerist 1, psychic 1, spiritualist 1<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You plumb the depths of your mind for insight, leaving you momentarily frazzled. When you are about to make a d20 roll based on Intelligence, Wisdom, or Charisma, you can cast this spell to gain a +8 enhancement bonus to Intelligence, Wisdom, or Charisma for that roll, but you are dazed for 1 round afterward.</p>
</>};
const _burst_of_nettles = {title: "Burst of Nettles", jsx: <><h2 id="spell-burst_of_nettles-burst-of-nettles">Burst of Nettles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> [<Link to="/spelldef/acid">acid</Link>]; <strong>Level</strong> druid 3, hunter 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 10-ft.-radius burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>You release a burst of barbed, acid-filled nettles. Creatures caught in the burst take 3d6 points of damage plus 1d6 points of acid damage on the next round. Those that save take half damage from the initial burst and no damage on the next round.</p>
</>};
const _burst_of_radiance = {title: "Burst of Radiance", jsx: <><h2 id="spell-burst_of_radiance-burst-of-radiance">Burst of Radiance</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/good">good</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> arcanist 2, cleric 2, druid 2, hunter 2, oracle 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a piece of flint and a pinch of silver dust)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Area</strong> 10-ft.-radius burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> yes</p><p>This spell fills the area with a brilliant flash of shimmering light. Creatures in the area are blinded for 1d4 rounds, or dazzled for 1d4 rounds if they succeed at a Reflex save. Evil creatures in the area of the burst take 1d4 points of damage per caster level (max 5d4), whether they succeed at the Reflex save or not.</p>
</>};
const _burst_of_speed = {title: "Burst of Speed", jsx: <><h2 id="spell-burst_of_speed-burst-of-speed">Burst of Speed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, antipaladin 3, bloodrager 3, hunter 3, inquisitor 3, investigator 3, magus 3, medium 3, paladin 3, psychic 3, ranger 3<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> see text</p><p>Until the end of your turn, you gain a +20 foot bonus to speed (or +10 foot bonus if you are wearing Medium or Heavy armor), your movement does not provoke attacks of opportunity, and you can move through the space of creatures that are larger than you are, but you cannot end your movement this round in a space occupied by a creature.</p>
</>};
const _burst_with_light = {title: "Burst with Light", jsx: <><h2 id="spell-burst_with_light-burst-with-light">Burst with Light</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/light">light</Link>]; <strong>Level</strong> cleric 4, oracle 4, paladin 4, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/4 levels<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> yes</p><p>The target becomes filled with intense magical light, taking 2d6 points of damage as the light bursts from its wounds and orifices (if the target is an undead creature, it instead takes 2d8 points of damage). In addition, the creature radiates bright light in a 30-foot radius and increases the light level by one step for an additional 30 feet beyond that area-darkness becomes dim light, dim light becomes normal light, and normal light becomes bright light. Creatures that take penalties in bright light take them while within the 30-foot radius of this magical light. A successful Will save halves the damage and negates the light effect.</p>
<p>For every 4 character levels you possess, the light continues to fill the creature for another round (to a maximum of 5 rounds at 20th level), though the target may make a Will save each round to halve the damage and end the effect. Any creature adjacent to the target that fails its save and takes damage takes half as much damage and is blinded for 1 round. A successful Reflex save halves this damage (to a total of one-quarter the damage taken by the target) and negates the blindness effect.</p>
</>};
const _business_booms = {title: "Business Booms", jsx: <><h2 id="spell-business_booms-business-booms">Business Booms</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link>; <strong>Level</strong> arcanist 3, bard 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (promotional materials such as flyers and posters worth 10 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one building<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You may cast this spell immediately prior to spending 1 day of downtime to <Link to="/rule/promote_a_business">promote a business</Link>. The spell is cast on a building you wish to promote, which is magically bestowed with magical decorations and other improvements that make it generally more appealing, and it is treated as seeing increased activity for the spell's duration. If the spell is cast on a building that you do not promote immediately thereafter, the spell is expended with no effect.</p>
<p>After the initial day of downtime spent promoting your building, the spell maintains the influx of activity for a number of days equal to half your caster level (maximum 5 days). During this time, you needn't spend additional downtime to promote the building, but you must spend capital as normal to promote the building. The capital the affected building generates for you is unaffected by the spell. If you spend 1 day promoting a different building than the target of this spell while this spell remains active, the spell immediately ends.</p>
</>};
const _cackling_skull = {title: "Cackling Skull", jsx: <><h2 id="spell-cackling_skull-cackling-skull">Cackling Skull</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> witch 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one skull<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as <Link to="/spell/magic_mouth">magic mouth</Link>, except rather than creating an illusory mouth on any surface, it affects a skull. In addition, when the skull's magic is triggered, it releases wild and unnerving cackles before speaking its message. All creatures that can hear the cackles must save or become shaken for 1d4 rounds.</p>
</>};
const _cacophonous_call = {title: "Cacophonous Call", jsx: <><h2 id="spell-cacophonous_call-cacophonous-call">Cacophonous Call</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> bard 2, skald 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a scrap of sheet music)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You fill your target's mind with a blaring cacophony of discordant sounds, making it hard for the target to act and concentrate. The creature gains the nauseated condition for the duration of the spell if it fails its Will save.</p>
<h3 id="spell-cacophonous_call-mass-cacophonous-call">Mass Cacophonous Call</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> bard 5, skald 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a scrap of sheet music)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature/level (all of which must be within 30 feet)<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as cacophonous call, except that it affects multiple creatures.</p>
</>};
const _caging_bomb_admixture = {title: "Caging Bomb Admixture", jsx: <><h2 id="spell-caging_bomb_admixture-caging-bomb-admixture">Caging Bomb Admixture</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> alchemist 6, investigator 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>Upon drinking an extract created with this formulae, you make a significant change to your magical reserve that modifies the nature of all bombs you create and throw during this extract's duration. This effect on your magical reserve has no effect on any discoveries that you use to modify your bombs, but you can only have one admixture effect (formulae with the word "bomb admixture" in its title) active at a time. If you drink another bomb admixture, the effects of the former bomb admixture end and the new one becomes active.</p>
<p>When you throw a bomb and hit a direct target, it creates an invisible cubical prison composed of a solid wall of force. The prison is as large as the splash area of the bomb that you threw, and traps any creature that is entirely inside the area.</p>
<p>Creatures within the area are caught and contained unless any creature within the splash radius is too big to fit inside, in which case the effect automatically fails. Teleportation and other forms of astral travel provide means for escape, but the force walls extend into the Ethereal Plane, blocking ethereal travel.</p>
<p>Like a <Link to="/spell/wall_of_force">wall of force</Link>, the cage created by the caging bomb admixture resists <Link to="/spell/dispel_magic">dispel magic</Link>, although a <Link to="/spell/mages_disjunction">mage's disjunction</Link> still functions. The walls of the cage can be damaged by spells as normal, except for <Link to="/spell/disintegrate">disintegrate</Link>, which automatically destroys the cage. The walls of this cage can be damaged by weapons and supernatural abilities, but the cage has a hardness of 20 and a number of hit points equal to 20 per alchemist level. Contact with a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link> or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> instantly destroys this cage.</p>
<p>When using caging bomb admixture, an alchemist can only have one cage in effect at a time. If the alchemist throws another bomb during the duration of caging bomb admixture, any other cage created by the earlier admixture ends, and a new one is created. When the duration of the caging bomb admixture ends, so does any remaining cage created by this admixture's effect.</p>
</>};
const _calamitous_flailing = {title: "Calamitous Flailing", jsx: <><h2 id="spell-calamitous_flailing-calamitous-flailing">Calamitous Flailing</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven pg. 20</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/curse">curse</Link>]; <strong>Level</strong> arcanist 4, bard 3, cleric 4, mesmerist 3, oracle 4, skald 3, sorcerer 4, spiritualist 3, warpriest 4, witch 3, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You cause the victim's attacks to careen wildly, endangering itself and those around it. Your target gains a 25% miss chance on all attack rolls. If an attack misses due to this magical effect, the victim instead targets an ally, or else itself if there are no allies within range of the original attack. Apply the attack roll for the original attack to the new target's Armor Class to determine if this attack hits. This is a curse effect.</p>
</>};
const _calcific_touch = {title: "Calcific Touch", jsx: <><h2 id="spell-calcific_touch-calcific-touch">Calcific Touch</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 208</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 4, bloodrager 4, psychic 4, red mantis assassin 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature or creatures touched (up to one per level)<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude partial; <strong>Spell Resistance</strong> yes</p><p>Your touch progressively transmutes the substance of creatures you touch into stone. Once per round, you may deliver a touch attack that inflicts 1d4 points of Dexterity damage and <Link to="/spell/slow">slows</Link> the target (as the spell) for 1 round. A successful Fortitude save negates the slow effect but not the ability damage. A target reduced to 0 Dexterity is petrified permanently. <Link to="/spell/break_enchantment">Break enchantment</Link>, <Link to="/spell/restoration">restoration</Link>, or <Link to="/spell/stone_to_flesh">stone to flesh</Link> can reverse the effects of calcific touch.</p>
</>};
const _calculated_luck = {title: "Calculated Luck", jsx: <><h2 id="spell-calculated_luck-calculated-luck">Calculated Luck</h2>
<p><strong>Sources</strong> <Link to="/source/occult_mysteries">Occult Mysteries pg. 50</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> cleric 3, oracle 3, warpriest 3, witch 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You are able to use the Path of Numbers to substantially boost your combat preparedness, but your foresight comes at a price. Roll 3d8 and refer to the <Link to="/rule/mathematical_spellcasting">Eight Basic Energies table</Link>. After rolling, assign each die to one of the following.</p>
<ul>
<li>Energy Type: You gain vulnerability to the energy type that matches the die's result for the duration of the spell. You take half again as much damage (+50%) from that energy type, regardless of whether you successfully saved against the damaging spell or effect.</li>
<li>Magic School: For the spell's duration, you cast all spells from the school that matches the die's result at +1 caster level.</li>
<li>d20 Roll Type: You receive a +2 luck bonus on the d20 roll that matches the die's result for the duration of the spell.</li>
</ul>
</>};
const _calistrias_guardian_wasps = {title: "Calistria's Guardian Wasps", jsx: <><h2 id="spell-calistrias_guardian_wasps-calistrias-guardian-wasps">Calistria's Guardian Wasps</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 58</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> arcanist 3, druid 3, hunter 3, psychic 3, ranger 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 10 minutes; see text<br/><strong>Components</strong> V, S, M (a glob of spiced honey)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> Swarm of wasps that builds a nest; see text<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You summon a <Link to="/monster/wasp_swarm">wasp swarm</Link> that builds a 10-foot-by-10-foot nest in the place you designate - typically under the eaves of a house, amid the rafters of a tavern, or in another obscured place. The wasp swarm takes the spell's casting time to build its nest; if the swarm is disrupted in any way (such as by being attacked) before you finish casting this spell, the wasps disappear and the spell fizzles.</p>
<p>Once the wasp swarm has built its nest, this spell also wards the area. As per alarm, when intruders that do not speak the password pass within 20 feet, the swarm is alerted and immediately leaves its nest and attacks the nearest intruder. The swarm pursues that intruder as best it can. Once the swarm attacks an intruder, you have no control over its target or direction of travel. When the spell ends, if the wasps have not left their nest, they and their nest disappear.</p>
</>};
const _call_animal = {title: "Call Animal", jsx: <><h2 id="spell-call_animal-call-animal">Call Animal</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 209</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> druid 1, hunter 1, mesmerist 1, ranger 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> see text<br/><strong>Effect</strong> one animal whose CR is equal or less than your caster level<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell calls the nearest wild animal of a particular type you designate (provided the animal's CR is equal to or less than your caster level) to seek you out. The animal moves toward you under its own power, so the time it takes to arrive depends on how close an animal of the desired type is when you cast the spell. If there is no animal of that type capable of reaching you within the spell's duration, you are aware of this fact, but the spell is wasted. Knowledge of the local fauna makes this spell more effective, and the GM may permit a Knowledge (nature) skill check (DC 15) to know what animals can be found in an area.</p>
<p>When the called animal arrives, it approaches to within 5 feet of you and remains nearby for the duration of the spell. Its starting attitude is indifferent, modified by circumstances and interaction. Other than starting attitude, this spell gives you no special influence or ability to communicate with the called animal, although you may use other spells or abilities to do so.</p>
<p>Once the spell's duration expires, the animal acts in accordance with its attitude. Most animals will likely wander off, but a hostile predatory animal may attack, especially if it is hungry or provoked.</p>
<p>Domesticated animals or animals trained by someone else, including such creatures as familiars or animal companions, are unaffected by call animals.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-call_animal--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Call Animal</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>You can call up to one animal per 2 caster levels. Animals that answer your call have a starting attitude of friendly. Add your tier to Handle Animal checks attempted to influence these animals.</p>
<p>You may use this spell to call magical beasts with Intelligence 1 or 2, but they can attempt Will saving throws (with a +4 bonus) to resist the spell.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _call_construct = {title: "Call Construct", jsx: <><h2 id="spell-call_construct-call-construct">Call Construct</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>); <strong>Level</strong> arcanist 8, cleric 8, occultist 6, oracle 8, psychic 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (a sapphire worth 1,000 or 5,000 gp; see text)<br/><strong>Range</strong> touch<br/><strong>Target</strong> construct touched<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions as <Link to="/spell/instant_summons">instant summons</Link>, except it can only summon a construct you control. For constructs such as golems that are immune to magic, the value of the specially inscribed sapphire must be at least 5,000 gp. For other constructs, a 1,000 gp sapphire suffices.</p>
<p>If the construct is no longer under your control or destroyed, the spell fails, but you know roughly where the construct or its remains are located.</p>
</>};
const _call_lightning = {hasJL:true,title: "Call Lightning", jsx: <><div className="jumpList" id="spell-call_lightning-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-call_lightning-mythic_call_lightning">Mythic Call Lightning</InnerLink></li><li><InnerLink toTop to="spell-call_lightning-call-lightning-storm">Call Lightning Storm</InnerLink></li></ul></div><h2 id="spell-call_lightning-call-lightning">Call Lightning</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 251</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> druid 3, hunter 3, occultist 3, shaman 3<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> one or more 30-ft.-long vertical lines of lightning<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>Immediately upon completion of the spell, and once per round thereafter, you may call down a 5-foot-wide, 30-foot-long, vertical bolt of lightning that deals 3d6 points of electricity damage. The bolt of lightning flashes down in a vertical stroke at whatever target point you choose within the spell's range (measured from your position at the time). Any creature in the target square or in the path of the bolt is affected.</p>
<p>You need not call a bolt of lightning immediately; other actions, even spellcasting, can be performed first. Each round after the first you may use a standard action (concentrating on the spell) to call a bolt. You may call a total number of bolts equal to your caster level (maximum 10 bolts).</p>
<p>If you are outdoors and in a stormy area - a rain shower, clouds and wind, hot and cloudy conditions, or even a tornado (including a whirlwind formed by a djinni or an air elemental of at least Large size)-each bolt deals 3d10 points of electricity damage instead of 3d6.</p>
<p>This spell functions indoors or underground but not underwater.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-call_lightning--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-call_lightning-mythic_call_lightning" data-hash-target>Mythic Call Lightning</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link></p>
<p>Each lightning bolt's damage increases to 3d10 points of damage (or 5d10 points outdoors in stormy weather). Half of this damage is electricity damage, and the other half is sonic. Creatures that succeed at their saving throws are dazzled and deafened for 1 round. Those that fail at their saving throws are dazzled and deafened for 1 minute.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-call_lightning-call-lightning-storm" data-hash-target>Call Lightning Storm</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 252</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> druid 5, hunter 5, occultist 5, shaman 5<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> one or more 30-ft.-long vertical lines of lightning<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>This spell functions like call lightning, except that each bolt deals 5d6 points of electricity damage (or 5d10 if created outdoors in a stormy area), and you may call a maximum of 15 bolts.</p>
</>};
const _call_spirit = {title: "Call Spirit", jsx: <><h2 id="spell-call_spirit-call-spirit">Call Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 160</Link>, <Link to="/source/occult_mysteries">Occult Mysteries pg. 54</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/calling">calling</Link>); <strong>Level</strong> cleric 5, medium 3, oracle 5, shaman 5, spiritualist 5, warpriest 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 10 ft.<br/><strong>Effect</strong> call the spirit of a single deceased humanoid creature<br/><strong>Duration</strong> concentration<br/><strong>Saving Throw</strong> Will negates, see text; <strong>Spell Resistance</strong> no</p><p>You attempt to cause the spirit of a specific individual to manifest from its final resting place. You must request the spirit's presence by speaking its name.</p>
<p>Unwilling spirits can resist the summons by succeeding at a Will save. If the chosen spirit resists your call, another spirit with malevolent intent almost always takes its place, intent on deceiving you. The difficulty of the save depends on how well you know the subject and what sort of physical connection (if any) you have to the creature whose spirit you wish to call.</p>
<ScrollContainer id="spell-call_spirit--table-0"><table>
<thead>
<tr>
<th>Knowledge</th>
<th>Will Save Modifier</th>
</tr>
</thead>
<tbody><tr>
<td>Name only<sup><InnerLink showBacklink="backlink-spell-call_spirit-ref-N-1" id="spell-call_spirit-ref-N-1" data-hash-target to="spell-call_spirit-N">1</InnerLink></sup></td>
<td>+15</td>
</tr>
<tr>
<td>Secondhand (you have heard of the subject)</td>
<td>+10</td>
</tr>
<tr>
<td>Firsthand (you met the subject in life)</td>
<td>+5</td>
</tr>
<tr>
<td>Familiar (you knew the subject well)</td>
<td>+0</td>
</tr>
</tbody></table></ScrollContainer>
<ScrollContainer id="spell-call_spirit--table-1"><table>
<thead>
<tr>
<th>Connection</th>
<th>Will Save Modifier</th>
</tr>
</thead>
<tbody><tr>
<td>Likeness or picture</td>
<td>-2</td>
</tr>
<tr>
<td>Possession or garment</td>
<td>-4</td>
</tr>
<tr>
<td>Body part, lock of hair, nail clipping, etc.</td>
<td>-10</td>
</tr>
<tr>
<td>Different alignment</td>
<td>+4</td>
</tr>
</tbody></table></ScrollContainer>
<p>A successfully called spirit manifests as a wispy, vaporous form that vaguely resembles the form the deceased creature had in life. The spirit has the physical attributes of an unseen servant and is capable of minor physical manipulations, with the ability to speak in quiet, ghostly whispers in whatever languages the creature knew while it was alive. The spirit isn't an undead creature, and isn't beholden to its caller. Whether you summoned the chosen spirit or a deceitful replacement, the spirit can refuse to answer your questions or attempt to deceive you using Bluff, though in either case these spirits can speak about only what they knew in life and have no knowledge of events that occurred after their deaths. Malevolent spirits might take advantage of their limited physical abilities to cause terrifying spectacles designed to scare the caster.</p>
<p>You must concentrate on maintaining the spell (as a standard action) in order to ask questions at the rate of one per round. You can ask a total of one question per caster level; the spirit answers each during the same round. When the spell ends, the spirit's ectoplasmic form fades and the soul returns to its rest. This spell can't call the spirits of creatures that are currently undead.</p>
<section data-footnotes>
<h3 id="spell-call_spirit-label">Footnotes</h3>
<ol>
<li id="spell-call_spirit-N">
<p>You must have at least a name the creature was called in life. <InnerLink id="backlink-spell-call_spirit-ref-N-1" data-hash-target to="spell-call_spirit-ref-N-1" aria-label="Back to reference N-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _call_the_void = {title: "Call the Void", jsx: <><h2 id="spell-call_the_void-call-the-void">Call the Void</h2>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> arcanist 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Reflex for half, see text; <strong>Spell Resistance</strong> yes</p><p>This spell surrounds you with an aura of nothingness that channels the mysterious energies of the Dark Tapestry. Creatures adjacent to you when this spell is cast and at the start of your turn take 2d6 points of damage. In addition, creatures affected by your aura are fatigued, cannot breathe, and cannot speak or cast spells with somatic components. Creatures adjacent to you are allowed a Reflex save to halve the damage and negate the fatigue effect, but cannot breathe or speak regardless of whether their save is successful as long as they are adjacent to you.</p>
</>};
const _call_weapon = {title: "Call Weapon", jsx: <><h2 id="spell-call_weapon-call-weapon">Call Weapon</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 53</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> bard 1, hunter 1, magus 1, ranger 1, skald 1<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 30 ft.<br/><strong>Target</strong> one melee weapon wielded by an ally<br/><strong>Duration</strong> instantaneous</p><p>This spell first rose to prominence among the elves of Kyonin in the war to retake their ancestral land from the demon lord Treerazer and his minions. Elite units of elven magi entered battle with this spell prepared to shield fallen comrades or stand firm against fell foes. As the elven presence returned to the world, this spell spread throughout the Inner Sea and beyond.</p>
<p>When you cast this spell, you cause a weapon wielded by an ally within 30 feet to telekinetically fly across the space between you and into your open hand. This extra energy persists in the weapon for the rest of the round, granting you a +2 circumstance bonus on attack rolls and weapon damage rolls made during the same round you cast this spell.</p>
<p>If the ally targeted for this spell is unwilling to give up her weapon, the spell fails. An unconscious or dying ally is considered a "willing" target so long as the weapon to be called is still in contact with the ally's body.</p>
</>};
const _callback = {title: "Callback", jsx: <><h2 id="spell-callback-callback">Callback</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 228</Link>, <Link to="/source/familiar_folio">Familiar Folio pg. 22</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>); <strong>Level</strong> arcanist 2, shaman 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a crushed grasshopper)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> your familiar or spirit animal<br/><strong>Duration</strong> 10 minutes/level or until expended (see text)<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>If the target takes hit point damage while within range of this spell, it immediately teleports to your space (or adjacent to your space) after the damage is applied. If the target is killed, its corpse teleports instead. Optionally, you can specify a number of points of damage for your familiar to take before the spell takes effect, but you must do so when the spell is cast. Once the familiar has teleported back to you, the spell ends.</p>
<h3 id="spell-callback-greater-callback">Greater Callback</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 228</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>); <strong>Level</strong> arcanist 5, shaman 5, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a crushed grasshopper)<br/><strong>Range</strong> 1 mile/level<br/><strong>Target</strong> your familiar or spirit animal<br/><strong>Duration</strong> 1 hour/level or until expended<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as callback, except as noted above.</p>
</>};
const _calm_air = {title: "Calm Air", jsx: <><h2 id="spell-calm_air-calm-air">Calm Air</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> arcanist 5, druid 4, hunter 4, sorcerer 5, summoner 4, unchained summoner 4, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Area</strong> cylinder (5-ft./level radius, 40 ft. high)<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong>  (object); <strong>Spell Resistance</strong> no (object)</p><p>This spell calms the air and disperses fog, dust, and other particles. The wind force in the area is reduced in strength by one step per 4 caster levels (to a minimum wind force of light) and clouds are dispersed, although parts of nonmagical clouds that extend beyond the area are not affected. If a magical cloud or wind's point of origin is inside the area of a calm air spell, the whole effect is suppressed; otherwise, only the part inside the area is suppressed. Suppression still counts against the duration of a wind or cloud effect. Magical wind and cloud effects are suppressed only if you succeed at a caster level check (DC 11 + effect's caster level). You can move the calm air effect by concentrating as a standard action.</p>
</>};
const _calm_animals = {title: "Calm Animals", jsx: <><h2 id="spell-calm_animals-calm-animals">Calm Animals</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 252</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> druid 1, hunter 1, psychic 1, ranger 1, shaman 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> animals within 30 ft. of each other<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell soothes and quiets animals, rendering them docile and harmless. Only ordinary animals (those with Intelligence scores of 1 or 2) can be affected by this spell. All the subjects must be of the same kind, and no two may be more than 30 feet apart. The maximum number of HD of animals you can affect is equal to 2d4 + caster level.</p>
<p>The affected creatures remain where they are and do not attack or flee. They are not helpless and defend themselves normally if attacked. Any threat breaks the spell on the threatened creatures.</p>
</>};
const _calm_emotions = {title: "Calm Emotions", jsx: <><h2 id="spell-calm_emotions-calm-emotions">Calm Emotions</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 252</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> bard 2, cleric 2, inquisitor 2, mesmerist 2, occultist 2, oracle 2, psychic 2, shaman 2, skald 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> creatures in a 20-ft.-radius spread<br/><strong>Duration</strong> concentration, up to 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell calms agitated creatures. You have no control over the affected creatures, but calm emotions can stop raging creatures from fighting or joyous ones from reveling. Creatures so affected cannot take violent actions (although they can defend themselves) or do anything destructive. Any aggressive action against or damage dealt to a calmed creature immediately breaks the spell on all calmed creatures.</p>
<p>This spell automatically suppresses (but does not dispel) any morale bonuses granted by spells such as bless, good hope, and rage, and also negates a bard's ability to inspire courage or a barbarian's rage ability. It also suppresses any fear effects and removes the confused condition from all targets. While the spell lasts, a suppressed spell, condition, or effect has no effect. When the calm emotions spell ends, the original spell or effect takes hold of the creature again, provided that its duration has not expired in the meantime.</p>
</>};
const _calm_spirit = {title: "Calm Spirit", jsx: <><h2 id="spell-calm_spirit-calm-spirit">Calm Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 160</Link>, <Link to="/source/occult_mysteries">Occult Mysteries pg. 55</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 2, medium 1, oracle 2, shaman 2, spiritualist 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one incorporeal undead creature or haunt<br/><strong>Duration</strong> 1 minute or 1 round/level; see text<br/><strong>Saving Throw</strong> Will negates or none, see text; <strong>Spell Resistance</strong> yes</p><p>This spell temporarily calms agitated haunts and incorporeal undead such as ghosts. You have no control over the affected creatures, but calm spirit postpones hostile action by the affected spirits for the duration of the spell. Entities so affected cannot take violent actions or do anything destructive, including triggering persistent haunt abilities, though they can defend themselves. Any aggressive action against or damage dealt to a calmed spirit or haunt immediately ends the effect.</p>
<p>Haunts do not receive a saving throw against the spell, but the caster must succeed at a caster level check whose difficulty is equal to at least 10 + the haunt's CR in order to temporarily calm the angry entity. The spell's duration changes to concentration (up to 1 round/level) when affecting a haunt.</p>
</>};
const _campfire_wall = {title: "Campfire Wall", jsx: <><h2 id="spell-campfire_wall-campfire-wall">Campfire Wall</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/light">light</Link>]; <strong>Level</strong> arcanist 3, bard 3, druid 2, hunter 2, occultist 2, ranger 2, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (ash made from burnt thorns)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> 20-ft.-radius sphere centered on fire source<br/><strong>Duration</strong> 2 hours/level; see below<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You can create a barrier around a fire of at least campfire size that shelters everyone inside so long as the fire continues to burn. The barrier appears as a crackling sphere of light and fire that is clearly visible, providing as much illumination as a torch. The barrier bocks line of sight, granting creatures on either side of the barrier <Link to="/rule/concealment">total concealment</Link> from creatures on the other side. Any object or creature passing through the barrier from outside takes 1d6 points of fire damage and is also outlined with light equivalent to that of a torch, for 1d6 minutes. Creatures outlined in this way are plainly visible regardless of the light conditions and do not benefit from any sort of concealment, magical or otherwise. The light is not bright enough to have any special effect on undead or creatures vulnerable to light. Creatures inside the barrier can leave without penalty, but if they try to return they suffer the same consequences as anyone else. If the fire source at the barrier's center is extinguished or moved, the spell ends.</p>
</>};
const _canopic_conversion = {title: "Canopic Conversion", jsx: <><h2 id="spell-canopic_conversion-canopic-conversion">Canopic Conversion</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 60</Link>, <Link to="/source/osirion_land_of_the_pharaohs">Osirion, Land of the Pharaohs pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/death">death</Link>, <Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 9, cleric 9, oracle 9, sorcerer 9, wizard 9<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (black onyx worth 100 gp per hit die of the target), F (four alabaster canopic jars worth 100 gp each)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living humanoid<br/><strong>Duration</strong> instantaneous and see text<br/><strong>Saving Throw</strong> Fortitude half; <strong>Spell Resistance</strong> yes</p><p>This spell eviscerates the target, drawing forth its life essence as well as its internal organs. The target takes 1d6 hit points of damage per caster level (maximum 20d6). If this damage kills the target, the spell pulls the creature's organs into a set of 4 canopic jars and seals them; 1d4 rounds later, the corpse revives as a mummy (if 8 HD or fewer) or an advanced mummy (if 9 HD or more).</p>
<p>The mummy is not under your control, but the canopic jars give the bearer certain powers over it. Anyone holding one of the jars can communicate with the mummy as if the two shared a common language. The bearer gains the benefits of <Link to="/spell/protection_from_evil">protection from evil</Link> and <Link to="/spell/sanctuary">sanctuary</Link>, but only against that mummy. Unsealing or breaking a jar is a standard action, which dissipates its power (and protection) but lets the bearer issue a short command to the mummy, similar to a suggestion spell (Will DC 23 negates). You (and only you) may unseal all 4 jars in a 10-minute ritual to control the mummy with an effect similar to geas (Will DC 23 negates); most casters typically include a restriction that the mummy will not harm them, as unsealing the jars leaves them vulnerable.</p>
<p>The pharaohs of ancient Osirion sometimes used this spell to punish their enemies. The <Link to="/rule/risen_guard">Risen Guard</Link> does not use the spell (though they have access to it), preferring trustworthy living guardians for the Ruby Prince. The <Link to="/rule/whispering_way">Whispering Way</Link> may have copies of the spell.</p>
</>};
const _cape_of_wasps = {title: "Cape of Wasps", jsx: <><h2 id="spell-cape_of_wasps-cape-of-wasps">Cape of Wasps</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> druid 4, hunter 4, witch 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)</p><p>You summon a wasp swarm, which fills your space (up to 5 feet by 5 feet) but does not attack you. The dense cloud of vermin gives you partial <Link to="/rule/concealment">concealment</Link> against ranged attacks. Any creature that makes a successful melee attack against you takes 2d6 points of swarm damage and poison from the wasp swarm, but is not affected by the swarm's distraction ability. As a free action on your turn, you may have the swarm cling to you tightly, giving you a fly speed of 20 feet (poor maneuverability); when using the swarm to fly, it does not provide concealment or harm creatures that strike you. You can return the swarm to its protective shape as a free action on your turn.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-cape_of_wasps--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Cape of Wasps</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>The wasp swarm fills a 15-foot-by-15-foot space centered on you (or on 1 of your squares, if your space is larger than 1 square). Creatures in the area of the swarm are affected by it normally (including the swarm's distraction ability). Add your tier to the swarm's distraction DC.</p>
<p>When you use the swarm to fly, it fills only your space, your fly speed is 30 feet (average maneuverability), and the swarm still provides partial concealment against ranged attacks.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _carrion_compass = {title: "Carrion Compass", jsx: <><h2 id="spell-carrion_compass-carrion-compass">Carrion Compass</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 2, cleric 1, hunter 1, oracle 1, ranger 1, sorcerer 2, warpriest 1, witch 1, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one undead creature<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> no</p><p>You animate one of the target's fetid organs so that it leads you to the undead creature's most recent controller or the cause of the creature's undeath. The organ (typically the heart, the brain, or an eyeball) floats in front of you at chest level and slowly leads you to the undead creature's most recent controller at a rate of 30 feet per round, always staying within your range of vision. If the creature from which the organ originated had no controller, but rather was created deliberately by another creature, the organ instead leads you to that creator. If the undead was animated by an effect or event at a particular location, the organ leads you to that location. If the creature was animated by none of the methods above, if it was self-created, or if the creature's most recent controller no longer exists, the spell fails. Once the organ is within 10 feet of its intended destination, the spell ends, and the organ falls to the ground.</p>
<p>The organ cannot engage in combat or execute any other task aside from leading you to its intended target. It may pass through small slits and crevices, though it will not leave your range of vision. The organ cannot travel more than 5 miles from the spot where you cast the spell. If the undead creature to which the organ belonged is destroyed, the spell ends and the organ falls to the ground.</p>
</>};
const _carry_companion = {title: "Carry Companion", jsx: <><h2 id="spell-carry_companion-carry-companion">Carry Companion</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, druid 2, hunter 2, paladin 2, ranger 2, red mantis assassin 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of sand or limestone dust)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one willing creature touched<br/><strong>Duration</strong> permanent; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You touch an animal or magical beast that has a helpful attitude toward you, instantly transforming the creature into a miniature figurine of stone, small enough to fit into the palm of your hand. Creatures with an attitude of less than helpful will not tolerate this spell, and it automatically fails to work on them. An intelligent animal or magical beast must be a willing subject in order for this spell to take effect. Any items that the creature wears (such as a harness or saddle) or carries (such as those stowed in saddlebags) are transformed along with the creature.</p>
<p>While miniaturized, the creature is under an effect similar to that of a <Link to="/spell/flesh_to_stone">flesh to stone</Link> spell: It is mindless and inert, and does not seem alive when viewed with spells like <Link to="/spell/deathwatch">deathwatch</Link>. However, you may return the creature to its normal form at any time simply by placing the figurine on the ground, touching it, and uttering a word of command. Otherwise, the creature remains in miniature form unless the spell is broken, such as by <Link to="/spell/dispel_magic">dispel magic</Link> or stronger magic. Unlike a <em>flesh to stone</em> spell, a creature affected by <em>carry companion</em> is unaffected by <Link to="/spell/stone_to_flesh">stone to flesh</Link>. If the miniature figurine is broken or damaged, the creature (if returned to its original state) has similar damage or deformities.</p>
</>};
const _carrying_wind = {title: "Carrying Wind", jsx: <><h2 id="spell-carrying_wind-carrying-wind">Carrying Wind</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> druid 3, hunter 3, shaman 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level</p><p>When you cast this spell, a wind spirit envelopes you and carries you with it at your direction. You gain a +10 foot enhancement bonus to your base speed and fly speed while this spell is in effect. If you don't have a fly speed, you instead gain a fly speed of 10 feet with poor maneuverability. If your caster level is 10th-14th, the enhancement bonus to these speeds is feet (if applicable, your temporary fly speed is 20 feet with average maneuverability). If your caster level is 15th or higher, the enhancement bonus to these speeds is feet (if applicable, your temporary fly speed is 30 feet with average maneuverability).</p>
</>};
const _carve_passage = {title: "Carve Passage", jsx: <><h2 id="spell-carve_passage-carve-passage">Carve Passage</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 218</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 5, druid 5, hunter 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a tiny diamond pick worth 500 gp)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> dirt or loose rock in one 5-ft. cube/level<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em>The following spell is available to the indicated race or ethnicity: <Link to="/race/kobold">Kobold</Link></em></p>
</blockquote>
<p>You can excavate and move an amount of snow, earth, dust, sand, and loose or packed rocks or ice chunks (each no more than 5 feet in diameter) whose volume fills one 5-foot cube per level. If you are buried, you can open a space around yourself and use any remaining cubes for tunneling. This spell is otherwise similar to <Link to="/spell/expeditious_excavation">expeditious excavation</Link>. Carve passage has no effect on earth creatures or solid rock or ice.</p>
</>};
const _cast_out = {title: "Cast Out", jsx: <><h2 id="spell-cast_out-cast-out">Cast Out</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> inquisitor 3, medium 2, psychic 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>With a melee touch attack you blast a single creature and disrupt any magic controlling it. The target takes 2d8 points of damage + 1 point per caster level (maximum +15). In addition, you make a dispel check against any magic jar effect (including a ghost's malevolence ability) or enchantment (compulsion) spells on the target creature, starting with the highest level spells and proceeding to lower level spells. Treat this as a targeted <Link to="/spell/dispel_magic">dispel magic</Link> spell, except cast out can dispel one such spell for every four caster levels you possess. A successful Will save halves the damage and limits the dispelling to a single spell or effect.</p>
</>};
const _castigate = {title: "Castigate", jsx: <><h2 id="spell-castigate-castigate">Castigate</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/language_dependent">language-dependent</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> inquisitor 2, mesmerist 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 round/level or 1 round; see text<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>You compel the target to beg for forgiveness. On a failed save, the target cowers with fear. On a successful save, it is shaken for 1 round. Each round on its turn, a cowering subject may attempt a new save to end the effect. A creature who worships the same god as you takes a -2 penalty on its saving throw.</p>
<h3 id="spell-castigate-mass-castigate">Mass Castigate</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/language_dependent">language-dependent</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> inquisitor 5, mesmerist 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level or 1 round; see text<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>This spell functions as castigate, except it affects many creatures.</p>
</>};
const _catatonia = {title: "Catatonia", jsx: <><h2 id="spell-catatonia-catatonia">Catatonia</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 161</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> alchemist 2, arcanist 3, bard 2, cleric 3, investigator 2, medium 2, mesmerist 2, oracle 3, psychic 3, skald 2, sorcerer 3, spiritualist 2, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> touch<br/><strong>Target</strong> willing creature touched<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You touch the target and place it into a deathlike state that persists for the duration. The target appears to be dead, and any creature that interacts with the target must succeed at a DC 20 Heal check to recognize it is actually alive.</p>
<p>Until the spell ends, the target counts as if it were dead for the purpose of resolving any effects that target or affect only living creatures, but it doesn't count as undead. The subject is helpless, and can still be killed normally.</p>
<p>Any effect that would bring the creature back to life or animate it as an undead fails, but ends the catatonia. The target can be affected by spells that affect only objects, including animate objects (if the creature is Small) and teleport object. However, anything that would cause the body to change form (such as shrink item) fails and ends the catatonia. This doesn't prevent the effects of spells that simply deal damage or otherwise destroy objects.</p>
</>};
const _cats_grace = {title: "Cat's Grace", jsx: <><h2 id="spell-cats_grace-cats-grace">Cat's Grace</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 252</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> adept 2, alchemist 2, arcanist 2, bloodrager 2, bard 2, druid 2, hunter 2, investigator 2, magus 2, medium 2, mesmerist 2, psychic 2, ranger 2, red mantis assassin 2, skald 2, sorcerer 2, summoner 2, unchained summoner 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (pinch of cat fur)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>The transmuted creature becomes more graceful, agile, and coordinated. The spell grants a +4 enhancement bonus to Dexterity, adding the usual benefits to AC, Reflex saves, and other uses of the Dexterity modifier.</p>
<h3 id="spell-cats_grace-mass-cats-grace">Mass Cat's Grace</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 252</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 6, bard 6, druid 6, hunter 6, magus 6, psychic 6, skald 6, sorcerer 6, summoner 4, unchained summoner 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (pinch of cat fur)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>This spell functions like cat's grace, except it affects multiple creatures.</p>
</>};
const _cause_fear = {title: "Cause Fear", jsx: <><h2 id="spell-cause_fear-cause-fear">Cause Fear</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 252</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> adept 1, antipaladin 1, arcanist 1, bloodrager 1, bard 1, cleric 1, inquisitor 1, medium 1, mesmerist 1, occultist 1, oracle 1, psychic 1, shaman 1, skald 1, sorcerer 1, spiritualist 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature with 5 or fewer HD<br/><strong>Duration</strong> 1d4 rounds or 1 round; see text<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>The affected creature becomes frightened. If the subject succeeds on a Will save, it is shaken for 1 round. Creatures with 6 or more HD are immune to this effect. Cause fear counters and dispels <Link to="/spell/remove_fear">remove fear</Link>.</p>
</>};
const _caustic_blood = {title: "Caustic Blood", jsx: <><h2 id="spell-caustic_blood-caustic-blood">Caustic Blood</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 230</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/acid">acid</Link>]; <strong>Level</strong> alchemist 4, arcanist 5, bloodrager 4, cleric 5, druid 4, hunter 4, investigator 4, magus 4, oracle 5, sorcerer 5, summoner 4, unchained summoner 4, warpriest 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (vial of black adder venom)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Reflex half or negates, see text; <strong>Spell Resistance</strong> no</p><p>You imbue your blood with corrosive acid. Any time you take piercing or slashing damage, a spray of acidic blood spurts from your body in the direction of the opponent who inflicted the wound, dealing 1d6 points of acid damage per caster level (maximum 15d6, Reflex half). This spurt travels in a 10-foot line, damaging the first creature or object it touches, with no splash damage. After it contacts a creature or object, your acidic blood continues to burn that creature for 1 round, dealing 1d6 points of acid damage per 2 caster levels (maximum 7d6). A second successful Reflex save negates this additional damage.</p>
</>};
const _caustic_eruption = {title: "Caustic Eruption", jsx: <><h2 id="spell-caustic_eruption-caustic-eruption">Caustic Eruption</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/acid">acid</Link>]; <strong>Level</strong> arcanist 7, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> 30-ft.-radius burst<br/><strong>Duration</strong> instantaneous and 2 rounds; see text<br/><strong>Saving Throw</strong> Reflex half (see text); <strong>Spell Resistance</strong> no</p><p>Acid erupts from your space in all directions, causing 1d6 points of damage per caster level (maximum 20d6) to creatures and unattended objects in the area. On your turn in each of the next 2 rounds, creatures and objects that failed their saves against the initial burst take an additional 1d6 points of acid damage per 2 caster levels (maximum 10d6) unless the acid is neutralized, dispelled, or washed away.</p>
</>};
const _caustic_safeguard = {title: "Caustic Safeguard", jsx: <><h2 id="spell-caustic_safeguard-caustic-safeguard">Caustic Safeguard</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/acid">acid</Link>]; <strong>Level</strong> alchemist 3, arcanist 4, bloodrager 3, investigator 3, magus 3, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (a thin metal wire and a vial of acid)<br/><strong>Range</strong> touch<br/><strong>Target</strong> object touched<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Reflex half (see text); <strong>Spell Resistance</strong> no</p><p>You imbue a single object with an acidic protective ward. Any creature other than you that touches the object takes 1d6 points of acid damage per 2 caster levels (maximum 10d6; Reflex half). Each time the spell discharges, the number of damage dice it deals is halved (rounded down); when the spell's damage dice reach 0, the spell ends. While casting this spell, you can touch up to one creature per 4 caster levels, which allows them to handle the warded object without triggering this spell.</p>
</>};
const _cauterizing_weapon = {title: "Cauterizing Weapon", jsx: <><h2 id="spell-cauterizing_weapon-cauterizing-weapon">Cauterizing Weapon</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bard 2, hunter 2, magus 2, ranger 2, red mantis assassin 3, skald 2, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a gobbet of melted wax)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one weapon or 50 projectiles, all of which must be together at the time of casting<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>You infuse a weapon with faint but pernicious energy that stymies accelerated healing. Damage dealt by the weapon or ammunition is treated as acid, cold, electricity, and fire, but only for the purpose of negating a creature's regeneration. The weapon is also treated as silver and cold iron at 8th level and is treated as chaotic, evil, good, and lawful at 11th level for the purpose of negating regeneration.</p>
</>};
const _cave_fangs = {title: "Cave Fangs", jsx: <><h2 id="spell-cave_fangs-cave-fangs">Cave Fangs</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 228</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> druid 5, hunter 5, shaman 5, witch 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a sharp gemstone fragment worth 150 gp)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> one 5-ft. square/level (S); the area must be a stone surface<br/><strong>Duration</strong> 1 day/level or until triggered<br/><strong>Saving Throw</strong> Reflex half (see below); <strong>Spell Resistance</strong> no</p><p>You create a magical trap in the area that causes deadly stalactites or stalagmites to lurch out of the floor or ceiling of a stone surface to "bite" an intruder. The magical trap is triggered whenever a Small or larger creature (other than you or your animal companion, familiar, or spirit animal) moves through the affected area. The effect of cave fangs depends on whether you create stalactites or stalagmites (see below). You can place these trapped squares anywhere within the spell's range; they need not be adjacent to each other, and you can create any mix of stalactites and stalagmites you wish. Cave fangs can be detected and disarmed as per a magical trap with successful DC 30 Perception and Disable Device checks. All trapped squares created by a single casting are linked, and they are all disabled if one of them is. If you place the traps in an area that is occupied by a creature, the spell effect is triggered at the completion of the casting.</p>
<p><strong>Stalactites:</strong> Shards of rock drop from the ceiling, dealing 3d8 points of bludgeoning and piercing damage (Reflex half) and creating an area of dense rubble that costs 2 squares of movement to enter. Dense rubble adds 5 to the DC of Acrobatics checks and adds 2 to the DCs of Stealth checks. A creature that fails its Reflex save is pinned to the ground under stalactites and rubble, gaining the entangled condition until it can free itself with a successful DC 15 Strength check or DC 20 Escape Artist check. One Small or larger creature can automatically clear the rubble by working for 1 minute.</p>
<p><strong>Stalagmites:</strong> Piercing spires of rock erupt up from the ground, dealing 3d8 points of piercing damage and knocking the creature prone (a creature that succeeds at a Reflex saving throw takes half damage and avoids being knocked prone). Once the stalagmites appear, they function thereafter as spike stones for 1 minute per caster level and then crumble to dust.</p>
<p>If cave fangs is cast inside of a cave or cavern, each effect of the spell deals 4d8 points of damage instead of 3d8, and creatures that trigger the cave fangs take a -2 penalty on their saving throws against the spell's effect.</p>
</>};
const _celestial_companion = {title: "Celestial Companion", jsx: <><h2 id="spell-celestial_companion-celestial-companion">Celestial Companion</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 12</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, druid 2, hunter 2, paladin 1, ranger 2, shaman 2, sorcerer 2, summoner 1, unchained summoner 1, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> animal companion, eidolon, familiar, or mount<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You bestow divine protection on your companion. The target gains spell resistance equal to 5 plus half your caster level against spells and spell-like effects produced by evil creatures. The target also gains a +1 sacred bonus on saving throws and DR 5/evil or silver. Creatures under the effects of this spell often take on a celestial appearance, such as golden feathers or a radiant aura, but they are not truly celestial creatures.</p>
</>};
const _celestial_healing = {title: "Celestial Healing", jsx: <><h2 id="spell-celestial_healing-celestial-healing">Celestial Healing</h2>
<p><strong>Sources</strong> <Link to="/source/arcane_anthology">Arcane Anthology pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, cleric 1, magus 1, oracle 1, sorcerer 1, summoner 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (1 drop of blood from a good outsider or 1 dose of holy water)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/2 levels<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You anoint a wounded creature with the blood of an outsider with the good subtype (such as an angel) or holy water, giving it fast healing 1. The target radiates the aura of a good creature for the duration of the spell and can sense the righteousness of the magic, though this has no long-term effect on the target's alignment. If the target has its own evil aura, this is not suppressed by celestial healing, and can also be detected normally.</p>
</>};
const _celestial_healing_greater = {title: "Greater Celestial Healing", jsx: <><h2 id="spell-celestial_healing_greater-greater-celestial-healing">Greater Celestial Healing</h2>
<p><strong>Sources</strong> <Link to="/source/arcane_anthology">Arcane Anthology pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> arcanist 4, bloodrager 4, cleric 4, magus 4, oracle 4, sorcerer 4, summoner 4, warpriest 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (1 drop of blood from a good outsider or 1 dose of holy water)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/2 levels<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>As per celestial healing, except the target gains fast healing 4 and the target radiates the aura of a good cleric.</p>
</>};
const _ceremony = {hasJL:true,title: "Ceremony", jsx: <><div className="jumpList" id="spell-ceremony-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-ceremony-funeral">Funeral</InnerLink></li><li><InnerLink toTop to="spell-ceremony-holiday-fete">Holiday Fete</InnerLink></li><li><InnerLink toTop to="spell-ceremony-marriage">Marriage</InnerLink></li><li><InnerLink toTop to="spell-ceremony-naming">Naming</InnerLink></li><li><InnerLink toTop to="spell-ceremony-domain-ceremonies">Domain Ceremonies</InnerLink></li><li><InnerLink toTop to="spell-ceremony-air">Air</InnerLink></li><li><InnerLink toTop to="spell-ceremony-animal">Animal</InnerLink></li><li><InnerLink toTop to="spell-ceremony-artifice">Artifice</InnerLink></li><li><InnerLink toTop to="spell-ceremony-chaos">Chaos</InnerLink></li><li><InnerLink toTop to="spell-ceremony-charm">Charm</InnerLink></li><li><InnerLink toTop to="spell-ceremony-community">Community</InnerLink></li><li><InnerLink toTop to="spell-ceremony-darkness">Darkness</InnerLink></li><li><InnerLink toTop to="spell-ceremony-death">Death</InnerLink></li><li><InnerLink toTop to="spell-ceremony-destruction">Destruction</InnerLink></li><li><InnerLink toTop to="spell-ceremony-earth">Earth</InnerLink></li><li><InnerLink toTop to="spell-ceremony-evil">Evil</InnerLink></li><li><InnerLink toTop to="spell-ceremony-fire">Fire</InnerLink></li><li><InnerLink toTop to="spell-ceremony-glory">Glory</InnerLink></li><li><InnerLink toTop to="spell-ceremony-good">Good</InnerLink></li><li><InnerLink toTop to="spell-ceremony-healing">Healing</InnerLink></li><li><InnerLink toTop to="spell-ceremony-knowledge">Knowledge</InnerLink></li><li><InnerLink toTop to="spell-ceremony-law">Law</InnerLink></li><li><InnerLink toTop to="spell-ceremony-liberation">Liberation</InnerLink></li><li><InnerLink toTop to="spell-ceremony-luck">Luck</InnerLink></li><li><InnerLink toTop to="spell-ceremony-madness">Madness</InnerLink></li><li><InnerLink toTop to="spell-ceremony-magic">Magic</InnerLink></li><li><InnerLink toTop to="spell-ceremony-nobility">Nobility</InnerLink></li><li><InnerLink toTop to="spell-ceremony-plant">Plant</InnerLink></li><li><InnerLink toTop to="spell-ceremony-protection">Protection</InnerLink></li><li><InnerLink toTop to="spell-ceremony-repose">Repose</InnerLink></li><li><InnerLink toTop to="spell-ceremony-rune">Rune</InnerLink></li><li><InnerLink toTop to="spell-ceremony-scalykind">Scalykind</InnerLink></li><li><InnerLink toTop to="spell-ceremony-strength">Strength</InnerLink></li><li><InnerLink toTop to="spell-ceremony-sun">Sun</InnerLink></li><li><InnerLink toTop to="spell-ceremony-travel">Travel</InnerLink></li><li><InnerLink toTop to="spell-ceremony-trickery">Trickery</InnerLink></li><li><InnerLink toTop to="spell-ceremony-void">Void</InnerLink></li><li><InnerLink toTop to="spell-ceremony-war">War</InnerLink></li><li><InnerLink toTop to="spell-ceremony-water">Water</InnerLink></li><li><InnerLink toTop to="spell-ceremony-weather">Weather</InnerLink></li></ul></div><h2 id="spell-ceremony-ceremony">Ceremony</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> cleric 1, oracle 1, warpriest 1<br/><strong>Casting Time</strong> 8 hours<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch or medium (100 ft. + 10 ft./level) (see text)<br/><strong>Target</strong> willing, living creature or creatures touched or one creature/level (see text)<br/><strong>Duration</strong> 1 hour/level or 1 day/level (see text)<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes</p><p>You harness divine power to create one of four different ceremonies - a funeral, holiday fete, marriage, or naming - and can also create two domain-based ceremonies. Each ceremony provides a boon to two living, touched subjects for 1 hour per caster level, representing the divine gifts granted by your deity as well as the normal morale-boosting benefits of participating in an officiated ceremony. Bonuses granted by these boons are sacred bonuses if you channel positive energy or profane bonuses if you channel negative energy. (Bonuses in this section are referred to simply as sacred bonuses for ease of reading.) Only subjects whose alignments are within one step of your deity can be affected by this spell.</p>
<p>If you are using the <Link to="/rule/downtime">downtime system</Link>, you may use additional resources to augment the effect of a particular ceremony. You may spend 10 Goods, Labor, or Influence or 2 Magic to create a larger ceremony and grant an additional boon that lasts for 1 day per caster level (up to a maximum of 5 days). The type of capital spent should reflect the preparation required for the specific ceremony. Augmented boons affect the creatures touched as well as a number of intelligent, properly aligned creatures within medium range equal to your caster level (up to a maximum of 10 creatures), granting all subjects the benefits of the original boon as well as the benefits of an augmented boon, representing the divine gifts granted to these witnesses by your god.</p>
<p>Unless otherwise stated, use-activated abilities are supernatural abilities and abilities that emulate the effects of a spell are spell-like abilities; in either case, abilities granted by a boon are generally usable only once or until the duration of the spell ends, whichever comes first. Spell-like abilities are cast at a creature's highest caster level gained, or, if the creature has no caster level, CL 1st. Constant or passive effects and bonuses granted by this spell can be dispelled as normal, using your caster level to do so.</p>
<h4 id="spell-ceremony-funeral" data-hash-target>Funeral</h4>
<p>A funeral service must involve a corpse and at least one willing companion or next of kin. The subject gains a +2 sacred bonus against death effects.</p>
<h4 id="spell-ceremony-holiday-fete" data-hash-target>Holiday Fete</h4>
<p>A holiday fete may involve up to two willing creatures. The subject gains a +1 sacred bonus on Fortitude saves.</p>
<h4 id="spell-ceremony-marriage" data-hash-target>Marriage</h4>
<p>A marriage must involve two willing creatures. The subject gains a +1 sacred bonus on saves against fear and emotion effects.</p>
<h4 id="spell-ceremony-naming" data-hash-target>Naming</h4>
<p>A naming must involve a willing parent or parents and a newborn (who is touched but unaffected). The subject can use <Link to="/spell/sanctuary">sanctuary</Link> once.</p>
<p>The augmented versions of these four ceremonies are identical, granting the subject a +2 sacred bonus on all saving throws.</p>
<h4 id="spell-ceremony-domain-ceremonies" data-hash-target>Domain Ceremonies</h4>
<p>In addition to these four ceremonies, each cleric gains two more ceremonies according to her domain. The names of domain ceremonies and their relevant boons are listed below. Unless otherwise noted, each of the following ceremonies requires at least two willing subjects.</p>
<h5 id="spell-ceremony-air" data-hash-target>Air</h5>
<p><strong>Celebration of Storms.</strong> The subject can use <Link to="/spell/feather_fall">feather fall</Link> once.<br/><em>Augmented:</em> The subject gains a +4 sacred bonus on saves against effects with the air descriptor.</p>
<h5 id="spell-ceremony-animal" data-hash-target>Animal</h5>
<p><strong>Ritual of Beasts.</strong> The subject can use <Link to="/spell/speak_with_animals">speak with animals</Link> once (this effect lasts 3 rounds).<br/><em>Augmented:</em> The subject can use <Link to="/spell/charm_animal">charm animal</Link> once.</p>
<h5 id="spell-ceremony-artifice" data-hash-target>Artifice</h5>
<p><strong>Apparatus's Observance.</strong> The subject can heal a construct creature with a touch, healing 1d3 points of damage.<br/><em>Augmented:</em> The subject can heal a construct creature 1d6 points of damage.</p>
<h5 id="spell-ceremony-chaos" data-hash-target>Chaos</h5>
<p><strong>Anarchic Revelry.</strong> The subject can force a lawful-aligned foe within 30 feet to roll an attack roll twice and take the less favorable result. This ability must be announced before the first attack roll is made.<br/><em>Augmented:</em> The first time the subject deals damage to a foe with a melee attack, the attack is treated as chaotic for the purpose of overcoming DR.</p>
<h5 id="spell-ceremony-charm" data-hash-target>Charm</h5>
<p><strong>Jubilee of Delight.</strong> The subject gains a +2 sacred bonus on his next Bluff, Diplomacy, or Intimidate check.<br/><em>Augmented:</em> The subject gains a +2 sacred bonus on saving throws against charm and compulsion effects.</p>
<h5 id="spell-ceremony-community" data-hash-target>Community</h5>
<p><strong>Celebration of Bonding.</strong> As a standard action, the subject can heal a touched creature 1d6 points of nonlethal damage.<br/><em>Augmented:</em> The subject is cured of the fatigued, shaken, and sickened conditions.</p>
<h5 id="spell-ceremony-darkness" data-hash-target>Darkness</h5>
<p><strong>Glorify Shadows.</strong> The subject gains darkvision to a range of 30 feet (or increases current range of darkvision by 10 feet).<br/><em>Augmented:</em> The subject increases range of darkvision by 30 feet.</p>
<h5 id="spell-ceremony-death" data-hash-target>Death</h5>
<p><strong>Dance of the Dead.</strong> The subject can use <Link to="/spell/bleed">bleed</Link> up to three times.<br/><em>Augmented:</em> The subject can use <Link to="/spell/cause_fear">cause fear</Link> once.</p>
<h5 id="spell-ceremony-destruction" data-hash-target>Destruction</h5>
<p><strong>Day of Dismantling.</strong> The subject gains a +1 sacred bonus on attacks and damage rolls against inanimate objects.<br/><em>Augmented:</em> The bonus becomes +2.</p>
<h5 id="spell-ceremony-earth" data-hash-target>Earth</h5>
<p><strong>Festival of Soil.</strong> The subject can cast <Link to="/spell/plant_growth">plant growth</Link> (enrichment) once.<br/><em>Augmented:</em> The subject gains a +4 sacred bonus on saves against effects with the earth descriptor.</p>
<h5 id="spell-ceremony-evil" data-hash-target>Evil</h5>
<p><strong>Unholy Gala.</strong> The subject can cause a good-aligned foe to become sickened for 1 round as a melee touch attack.<br/><em>Augmented:</em> This boon can be used three times.</p>
<h5 id="spell-ceremony-fire" data-hash-target>Fire</h5>
<p><strong>Fire Calling.</strong> Nonmagical fires the subject makes cannot be extinguished by nonmagical means, though spells and other magical effects function as normal.<br/><em>Augmented:</em> The subject gains a +4 sacred bonus on saves against effects with the fire descriptor.</p>
<h5 id="spell-ceremony-glory" data-hash-target>Glory</h5>
<p><strong>Resplendent Feast.</strong> The subject receives a +2 bonus on a single Charisma-based skill check.<br/><em>Augmented:</em> This boon can be used three times.</p>
<h5 id="spell-ceremony-good" data-hash-target>Good</h5>
<p><strong>Festival of Benevolence.</strong> The subject gains a +1 sacred bonus on melee attacks and melee damage rolls against evil-aligned foes.<br/><em>Augmented:</em> The bonus becomes +2.</p>
<h5 id="spell-ceremony-healing" data-hash-target>Healing</h5>
<p><strong>Touch of Assuagement.</strong> The subject can heal a dying creature 1d4 hit points as a standard action.<br/><em>Augmented:</em> This boon can be used three times.</p>
<h5 id="spell-ceremony-knowledge" data-hash-target>Knowledge</h5>
<p><strong>Liturgy of Learning.</strong> The subject can attempt any Knowledge skill check untrained.<br/><em>Augmented:</em> This boon can be used three times.</p>
<h5 id="spell-ceremony-law" data-hash-target>Law</h5>
<p><strong>Observance of Order.</strong> The subject gains a +5 sacred bonus on the next combat maneuver check she makes against a chaotic-aligned foe.<br/><em>Augmented:</em> The subject gains a +2 sacred bonus to CMD against chaotic-aligned foes.</p>
<h5 id="spell-ceremony-liberation" data-hash-target>Liberation</h5>
<p><strong>Freedom Festival.</strong> The subject can use remove fear once.<br/><em>Augmented:</em> The subject gains a +2 sacred bonus to CMD.</p>
<h5 id="spell-ceremony-luck" data-hash-target>Luck</h5>
<p><strong>Fete of Fortune.</strong> The next time the subject rolls a d20, he may roll twice and take the more favorable result.<br/><em>Augmented:</em> The subject may use this ability on any single d20 roll, not just the next one.</p>
<h5 id="spell-ceremony-madness" data-hash-target>Madness</h5>
<p><strong>Rite of Insanity.</strong> The subject can, as a melee touch attack, cause a foe to become confused for 1d4 rounds (DC 13 Will negates).<br/><em>Augmented:</em> This boon can be used twice.</p>
<h5 id="spell-ceremony-magic" data-hash-target>Magic</h5>
<p><strong>Arcane Obeisance.</strong> The subject gains a +2 sacred bonus on Spellcraft checks made while researching a spell or crafting a magic item.<br/><em>Augmented:</em> The subject gains a +2 sacred bonus on Knowledge (arcana) or (religion) checks made while researching a spell.</p>
<h5 id="spell-ceremony-nobility" data-hash-target>Nobility</h5>
<p><strong>Knighting Ceremony.</strong> The subject receives a +1 sacred bonus on attack and damage rolls with one weapon of her choice.<br/><em>Augmented:</em> The bonus becomes +2.</p>
<h5 id="spell-ceremony-plant" data-hash-target>Plant</h5>
<p><strong>Harvest Festival.</strong> The subject can use <Link to="/spell/speak_with_plants">speak with plants</Link> once, but the duration is 1 minute.<br/><em>Augmented:</em> This boon can be used three times.</p>
<h5 id="spell-ceremony-protection" data-hash-target>Protection</h5>
<p><strong>Ceremony of Sanctuary.</strong> The subject can use <Link to="/spell/sanctuary">sanctuary</Link> once.<br/><em>Augmented:</em> The subject gains a +2 sacred bonus to AC.</p>
<h5 id="spell-ceremony-repose" data-hash-target>Repose</h5>
<p><strong>Spirit Ward.</strong> The subject can attempt a melee touch attack against a flat-footed foe to put him to sleep for 1d4 rounds.<br/><em>Augmented:</em> This boon can be used three times.</p>
<h5 id="spell-ceremony-rune" data-hash-target>Rune</h5>
<p><strong>Ancestral Observance.</strong> The subject gains a +2 sacred bonus on saves against language-dependent effects.<br/><em>Augmented:</em> The subject gains a +2 sacred bonus on Linguistics checks.</p>
<h5 id="spell-ceremony-scalykind" data-hash-target>Scalykind</h5>
<p><strong>Song of Serpents.</strong> The subject gains a +2 sacred bonus on saves against gaze attacks.<br/><em>Augmented:</em> The subject gains a +4 sacred bonus to AC against the distraction attack of swarms.</p>
<h5 id="spell-ceremony-strength" data-hash-target>Strength</h5>
<p><strong>Ritual of Might.</strong> The subject gains a +1 sacred bonus on Strength-based skill checks and Strength checks.<br/><em>Augmented:</em> The bonus becomes +2.</p>
<h5 id="spell-ceremony-sun" data-hash-target>Sun</h5>
<p><strong>Solstice Celebration.</strong> The illumination radius of any torch or other mundane light source held by the subject increases by 10 feet.<br/><em>Augmented:</em> The subject gains a +4 sacred bonus against effects with the light descriptor.</p>
<h5 id="spell-ceremony-travel" data-hash-target>Travel</h5>
<p><strong>Festival of Journeys.</strong> The subject can choose to ignore the effects of difficult terrain for 1 round.<br/><em>Augmented:</em> This boon may be used three times.</p>
<h5 id="spell-ceremony-trickery" data-hash-target>Trickery</h5>
<p><strong>Communion of Liars.</strong> The subject gains a +2 sacred bonus to AC the first time he is attacked while flanked.<br/><em>Augmented:</em> This boon functions the first three times the subject is attacked while flanked.</p>
<h5 id="spell-ceremony-void" data-hash-target>Void</h5>
<p><strong>Celestial Observance.</strong> The subject knows the direction of north from her current position for the duration of this spell.<br/><em>Augmented:</em> The subject is immune to confusion effects.</p>
<h5 id="spell-ceremony-war" data-hash-target>War</h5>
<p><strong>Call to Battle.</strong> The subject gains a +1 sacred bonus on attack rolls.<br/><em>Augmented:</em> The subject gains a +1 sacred bonus on damage rolls.</p>
<h5 id="spell-ceremony-water" data-hash-target>Water</h5>
<p><strong>Water Blessing.</strong> The subject can use water breathing.<br/><em>Augmented:</em> The subject gains a +4 sacred bonus on saves against effects with the water descriptor.</p>
<h5 id="spell-ceremony-weather" data-hash-target>Weather</h5>
<p><strong>Song of the Tempest.</strong> The subject can call one 10-foot-by-10-foot rain cloud in an area within 30 feet, requiring creatures in the affected area attempting to cast spells to first succeed at DC 13 <Link to="/rule/concentration">concentration</Link> checks for 1 round.<br/><em>Augmented:</em> The DC is 15 for 3 rounds.</p>
</>};
const _certain_grip = {title: "Certain Grip", jsx: <><h2 id="spell-certain_grip-certain-grip">Certain Grip</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 2, arcanist 2, bloodrager 2, druid 2, hunter 2, investigator 2, occultist 2, red mantis assassin 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a tiny ball of tar)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject's grip and footing become sure, granting a +4 competence bonus on Climb checks, on Acrobatics checks to balance, and to CMD against bull rush, drag, reposition, and trip attempts. While affected by this spell, the target is also immune to the disarm combat maneuver.</p>
</>};
const _chain_lightning = {title: "Chain Lightning", jsx: <><h2 id="spell-chain_lightning-chain-lightning">Chain Lightning</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 253</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/electricity">electricity</Link>]; <strong>Level</strong> arcanist 6, magus 6, occultist 6, sorcerer 6, witch 7, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a bit of fur, a piece of amber, glass, or a crystal rod; plus one silver pin per caster level)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Targets</strong> one primary target, plus one secondary target/level (each of which must be within 30 ft. of the primary target)<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>This spell creates an electrical discharge that begins as a single stroke commencing from your fingertips. Unlike lightning bolt, chain lightning strikes one object or creature initially, then arcs to other targets.</p>
<p>The bolt deals 1d6 points of electricity damage per caster level (maximum 20d6) to the primary target. After it strikes, lightning can arc to a number of secondary targets equal to your caster level (maximum 20). The secondary bolts each strike one target and deal as much damage as the primary bolt.</p>
<p>Each target can attempt a Reflex saving throw for half damage. The Reflex DC to halve the damage of the secondary bolts is 2 lower than the DC to halve the damage of the primary bolt. You choose secondary targets as you like, but they must all be within 30 feet of the primary target, and no target can be struck more than once. You can choose to affect fewer secondary targets than the maximum.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-chain_lightning--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Chain Lightning</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 87</Link><br/>This spell deals 1d10 points of damage per caster level (maximum 20d10) and the save DC isn't reduced for secondary targets. Secondary targets have to be within 30 feet of any other target, not necessarily the primary target.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _chain_of_perdition = {title: "Chain of Perdition", jsx: <><h2 id="spell-chain_of_perdition-chain-of-perdition">Chain of Perdition</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> arcanist 3, bloodrager 3, cleric 3, oracle 3, psychic 3, sorcerer 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (chain link)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> 10-ft. chain<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>A floating chain of force with hooks at each end appears within an unoccupied space of your choosing within range. This chain is a Medium object that has a 10-foot reach. Physical attacks cannot hit or harm the chain of perdition, but <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link>, or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> affects it normally. The chain's AC against touch attacks is 10 + your Charisma modifier (sorcerer), Intelligence modifier (wizard), or Wisdom modifier (cleric).</p>
<p>The chain can perform the dirty trick (blind or entangle), drag, reposition, and trip combat maneuvers, using your caster level in place of your Combat Maneuver Bonus, and your Charisma modifier (sorcerer), Intelligence modifier (wizard), or Wisdom modifier (cleric) in place of your Strength or Dexterity modifier. The chain does not provoke attacks of opportunity for making combat maneuvers. It suffers no penalty or miss chance due to darkness, invisibility, or other forms of concealment.</p>
<p>As a move action, you can move the chain up to 30 feet. If the chain goes beyond the spell's range or out of your sight, it returns to you.</p>
<p>If a creature that the chain attacks has spell resistance, you must make a caster level check (1d20 + caster level) against that spell resistance the first time the chain performs a successful maneuver against that creature. If the chain is successfully resisted, the spell is dispelled. If not, the weapon has its normal full effect on that creature for the duration of the spell.</p>
</>};
const _chains_of_fire = {title: "Chains of Fire", jsx: <><h2 id="spell-chains_of_fire-chains-of-fire">Chains of Fire</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 131</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 6, magus 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a drop of oil and a small piece of flint)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> one primary target, plus one secondary target/level (each of which must be within 30 ft. of the primary target)<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/race/ifrit">Ifrits</Link> have access to the following spell.</em></p>
</blockquote>
<p>This spell functions like chain lightning, except as noted above, and the spell deals fire damage instead of electricity damage.</p>
</>};
const _chains_of_light = {title: "Chains of Light", jsx: <><h2 id="spell-chains_of_light-chains-of-light">Chains of Light</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> arcanist 6, cleric 6, inquisitor 5, oracle 6, paladin 4, sorcerer 6, warpriest 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a length of fine golden chain)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Reflex negates; <strong>Spell Resistance</strong> no</p><p>A creature targeted by this spell is held immobile by glowing golden chains composed of pure light. The creature is paralyzed and held in place, but may attempt a new saving throw each round to end the effect. While held by the golden chains, a creature cannot use any sort of extradimensional travel, such as <Link to="/spell/astral_projection">astral projection</Link>, <Link to="/spell/blink">blink</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>, <Link to="/spell/etherealness">etherealness</Link>, <Link to="/spell/gate">gate</Link>, <Link to="/spell/maze">maze</Link>, <Link to="/spell/plane_shift">plane shift</Link>, <Link to="/spell/shadow_walk">shadow walk</Link>, <Link to="/spell/teleport">teleport</Link>, and similar spells and spell-like abilities. The spell does not affect creatures that are already in ethereal or astral form when the spell is cast.</p>
</>};
const _challenge_evil = {title: "Challenge Evil", jsx: <><h2 id="spell-challenge_evil-challenge-evil">Challenge Evil</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> paladin 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one evil creature<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You challenge an evil creature to bring the fight to you, or suffer the consequences. You gain a +2 sacred bonus on all melee attacks against the subject of the spell. At the end of its turn, if the target has not made at least one attack on you, it becomes sickened. If you move away from the target, the spell ends.</p>
</>};
const _chameleon_scales = {title: "Chameleon Scales", jsx: <><h2 id="spell-chameleon_scales-chameleon-scales">Chameleon Scales</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 1, arcanist 0, druid 0, hunter 0, investigator 1, ranger 1, sorcerer 0, wizard 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)</p><p>You temporarily alter the color of your skin, hide, or scales to another option legal for your race. You take no penalty for using Disguise to appear as a member of a different race as long as that race has the same type and color of skin, hide, or scales as you.</p>
</>};
const _chameleon_stride = {title: "Chameleon Stride", jsx: <><h2 id="spell-chameleon_stride-chameleon-stride">Chameleon Stride</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> hunter 2, ranger 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You fade into the background, and while you are not truly invisible, you are hard to pinpoint due to your translucent state. While under the effects of this spell, you gain a +4 bonus on Stealth checks and have concealment from creatures more than 5 feet away (attacks have a 20% miss chance).</p>
<h3 id="spell-chameleon_stride-greater-chameleon-stride">Greater Chameleon Stride</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 177</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> hunter 3, ranger 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 5 ft.<br/><strong>Area</strong> allies in a 10-ft.-radius emanation centered on you<br/><strong>Duration</strong> 1 minute/level (see text)</p><p>This spell functions as chameleon stride, except it confers its bonuses upon all allies within 10 feet of you at the time the spell is cast. Those affected by this spell are able to see each other and themselves as if they were unaffected by the spell. If an affected creature moves out of the area, it loses the benefit of the spell. Creatures that move into the area after the spell is cast do not gain its benefit.</p>
</>};
const _champions_bout = {title: "Champion's Bout", jsx: <><h2 id="spell-champions_bout-champions-bout">Champion's Bout</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 218</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> bard 3, cleric 3, oracle 3, skald 3, warpriest 3<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> two creatures<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes (see text)</p><blockquote>
<p><em>The following spell is available to the indicated race or ethnicity: Shoanti</em></p>
</blockquote>
<p>You allow two chosen champions to fight without interference. The two creatures must be willing in order for the spell to work. After you cast this spell, any creature attempting to aid or hinder either of the two targets in any way must succeed at a Will save or lose its action instead (spell resistance applies). A creature that fails its Will save against champion's bout cannot attempt to interfere again. If a creature successfully interferes with the bout, the spell ends immediately.</p>
</>};
const _changestaff = {title: "Changestaff", jsx: <><h2 id="spell-changestaff-changestaff">Changestaff</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 253</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 7<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, F (a quarterstaff that has been carved and polished for 28 days)<br/><strong>Range</strong> touch<br/><strong>Target</strong> your touched staff<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You change a specially prepared quarterstaff into a Huge treant-like creature, about 24 feet tall. When you plant the end of the staff in the ground and speak a special command to conclude the casting of the spell, your staff turns into a creature that looks and fights just like a treant. The staff-treant defends you and obeys any spoken commands. However, it is by no means a true treant; it cannot converse with actual treants or control trees. If the staff-treant is reduced to 0 or fewer hit points, it crumbles to powder and the staff is destroyed. Otherwise, the staff returns to its normal form when the spell duration expires (or when the spell is dismissed), and it can be used as the focus for another casting of the spell. The staff-treant is always at full strength when created, despite any wounds it may have incurred the last time it appeared.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-changestaff--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Changestaff</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>The treant-like creature created with this spell is considered a mythic creature, and it gains DR 10/epic and slashing instead of gaining DR 10/slashing.</p>
<p><em>Augmented (7th):</em> If you expend two uses of mythic power, the creature gains the savage <Link to="/rule/mythic_simple_templates">mythic template</Link>.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _channel_the_gift = {title: "Channel the Gift", jsx: <><h2 id="spell-channel_the_gift-channel-the-gift">Channel the Gift</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 230</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> arcanist 3, bard 3, cleric 3, druid 3, hunter 3, oracle 3, ranger 3, skald 3, sorcerer 3, warpriest 3, witch 3, wizard 3 (Nethys; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> ally spellcaster touched<br/><strong>Duration</strong> 1 round or see text<br/><strong>Saving Throw</strong> Will negates (harmless) or none; <strong>Spell Resistance</strong> yes (harmless) or no</p><p>You channel your magical power to fuel the target's spellcasting. The next spell the target casts of 3rd level or lower does not expend a spell slot; in effect, you are using your spell slot to power the target's spell. The target must start casting this spell before your next turn, and the spell cannot have a casting time longer than 1 full round. Your alignment, prohibited wizard school, and other restrictions on your own spellcasting do not affect the target, nor do you suffer any backlash from the target's choice of spell.</p>
<p>If you target yourself with this spell, you may spontaneously cast any prepared spell of 3rd level or lower without expending its spell slot on your next turn (this aspect of the spell has no effect if you are a spontaneous caster). The spell that's cast after channel the gift cannot have a casting time longer than 1 full round.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _channel_vigor = {title: "Channel Vigor", jsx: <><h2 id="spell-channel_vigor-channel-vigor">Channel Vigor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 231</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 23</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 3, bloodrager 3, cleric 3, inquisitor 3, investigator 3, magus 3, oracle 3, warpriest 3 (Irori; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>You focus the energy of your mind, body, and spirit into a specific part of your being, granting yourself an exceptional ability to perform certain tasks. When you cast the spell, choose one of the following portions of your self as your focus target. Thereafter, you may change the focus target as a move action. You can gain the benefit of only one channel vigor spell at a time.</p>
<p><em>Limbs:</em> You gain the benefits of a haste spell.</p>
<p><em>Mind:</em> You gain a +4 competence bonus on Knowledge and Perception skill checks and on ranged attack rolls.</p>
<p><em>Spirit:</em> You gain a +6 competence bonus on Will saving throws and Bluff and Intimidate checks.</p>
<p><em>Torso:</em> You gain a +6 competence bonus on Fortitude saving throws and <Link to="/rule/concentration">concentration</Link> checks.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _chaos_hammer = {title: "Chaos Hammer", jsx: <><h2 id="spell-chaos_hammer-chaos-hammer">Chaos Hammer</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 254</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/chaotic">chaotic</Link>]; <strong>Level</strong> cleric 4, inquisitor 4, oracle 4, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> 20-ft.-radius burst<br/><strong>Duration</strong> instantaneous (1d6 rounds); see text<br/><strong>Saving Throw</strong> Will partial; see text; <strong>Spell Resistance</strong> yes</p><p>You unleash chaotic power to smite your enemies. The power takes the form of a multicolored explosion of leaping, ricocheting energy. Only lawful and neutral (not chaotic) creatures are harmed by the spell.</p>
<p>The spell deals 1d8 points of damage per two caster levels (maximum 5d8) to lawful creatures (or 1d6 points of damage per caster level, maximum 10d6, to lawful outsiders) and slows them for 1d6 rounds (see the <Link to="/spell/slow">slow</Link> spell). A successful Will save reduces the damage by half and negates the slow effect.</p>
<p>The spell deals only half damage against creatures who are neither lawful nor chaotic, and they are not slowed. Such a creature can reduce the damage by half again (down to one-quarter) with a successful Will save.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-chaos_hammer--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Chaos Hammer</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>The damage dealt to lawful outsiders increases to 1d10 points of damage per caster level (maximum 10d10), and the damage dealt to other lawful creatures increases to 1d12 points of damage per 2 caster levels (maximum 5d12). The duration of slow increases to 2d6 rounds. Lawful creatures that succeed at their saves are slowed for 1 round.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _charge_object = {title: "Charge Object", jsx: <><h2 id="spell-charge_object-charge-object">Charge Object</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 161</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> medium 1, mesmerist 1, occultist 1, psychic 1, spiritualist 1<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> object touched<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> none, see text; <strong>Spell Resistance</strong> no</p><p>You charge an item with minor psychic energy. The item can be detected by the <Link to="/spell/detect_psychic_significance">detect psychic significance</Link> spell. If you wish, you can imprint the item with your ownership history. Spells such as <Link to="/spell/object_reading">object reading</Link> and uses of the <Link to="/skill/psychometry">psychometry</Link> unlock can reveal any information about yourself you impart into the object, including your name, alignment, profession, and a summary of your experiences with the item. You can't impart false information into the object, but you can omit any details you'd prefer not to divulge. If the target object is already psychically charged, you can add more information to it, but you can't use charge object to erase existing psychic information.</p>
</>};
const _charitable_impulse = {title: "Charitable Impulse", jsx: <><h2 id="spell-charitable_impulse-charitable-impulse">Charitable Impulse</h2>
<p><strong>Sources</strong> <Link to="/source/chronicle_of_the_righteous">Chronicle of the Righteous pg. 50</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bard 2, cleric 3, oracle 3, skald 2, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F/DF (a miniature collection plate)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one humanoid creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell makes a creature more charitable, compelling it to aid others rather than use violence. An affected creature practices non-violent combat behaviors according to the following list of priorities, beginning with the first priority. The subject continues to perform a priority until he can no longer fulfill its demands (at which point he moves to the next priority) or until the spell ends, whichever comes first.</p>
<p><em>1st Priority:</em> Heal injured creatures within 30 feet, beginning with the closest creatures and using whatever methods the subject has at hand (including potions, spells, and so on).</p>
<p><em>2nd Priority:</em> The subject gives his weapon away to the nearest creature within 30 feet who will accept it. If no creature accepts the weapon, the subject drops the weapon on the ground.</p>
<p><em>3rd Priority:</em> Cast beneficial spells and/or use beneficial magic items (including potions, wands, and so on) on creatures within 30 feet, starting with the closest creatures.</p>
<p><em>4th Priority:</em> The subject gives away his non-worn possessions - the contents of a backpack or similar item count as one item each, as does the container itself - to creatures within 30 feet. If no creature accepts the items, the subject drops the items on the ground.</p>
<p><em>5th Priority:</em> The subject gives away his remaining possessions (including his armor, boots, cloak, and so on) to creatures within 30 feet. If no creature accepts the items, the subject drops them on the ground.</p>
<p>If the subject fulfills all five priorities, the spell effect ends. The subject cannot attack or take attacks of opportunity, but can defend himself as normal. If the subject is attacked, the spell's effect immediately ends.</p>
</>};
const _charm_animal = {title: "Charm Animal", jsx: <><h2 id="spell-charm_animal-charm-animal">Charm Animal</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 254</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> druid 1, hunter 1, psychic 1, ranger 1, shaman 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one animal<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like charm person, except that it affects a creature of the animal type.</p>
</>};
const _charm_monster = {title: "Charm Monster", jsx: <><h2 id="spell-charm_monster-charm-monster">Charm Monster</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 254</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 4, bard 3, mesmerist 3, occultist 4, psychic 4, skald 3, sorcerer 4, summoner 3, unchained summoner 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like charm person, except that the effect is not restricted by creature type or size.</p>
<h3 id="spell-charm_monster-mass-charm-monster">Mass Charm Monster</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 254</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 8, bard 6, mesmerist 6, occultist 6, psychic 8, skald 6, sorcerer 8, summoner 6, witch 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one or more creatures, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like charm monster, except that mass charm monster affects a number of creatures whose combined HD do not exceed twice your level, or at least one creature regardless of HD. If there are more potential targets than you can affect, you choose them one at a time until you must choose a creature with too many HD to affect.</p>
</>};
const _charm_person = {hasJL:true,title: "Charm Person", jsx: <><div className="jumpList" id="spell-charm_person-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-charm_person-charm-fey">Charm Fey</InnerLink></li><li><InnerLink toTop to="spell-charm_person-mass-charm-person">Mass Charm Person</InnerLink></li></ul></div><h2 id="spell-charm_person-charm-person">Charm Person</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 254</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 1, bard 1, mesmerist 1, occultist 1, psychic 1, shaman 1, skald 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one humanoid creature<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This charm makes a humanoid creature regard you as its trusted friend and ally (treat the target's attitude as friendly). If the creature is currently being threatened or attacked by you or your allies, however, it receives a +5 bonus on its saving throw.</p>
<p>The spell does not enable you to control the charmed person as if it were an automaton, but it perceives your words and actions in the most favorable way. You can try to give the subject orders, but you must win an opposed Charisma check to convince it to do anything it wouldn't ordinarily do. (Retries are not allowed.) An affected creature never obeys suicidal or obviously harmful orders, but it might be convinced that something very dangerous is worth doing. Any act by you or your apparent allies that threatens the charmed person breaks the spell. You must speak the person's language to communicate your commands, or else be good at pantomiming.</p>
<h3 id="spell-charm_person-charm-fey" data-hash-target>Charm Fey</h3>
<p><strong>Sources</strong> <Link to="/source/the_first_world_realm_of_the_fey">The First World, Realm of the Fey pg. 12</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 1, bard 1, skald 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one fey creature<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as charm person, except it affects a fey instead of a humanoid.</p>
<h3 id="spell-charm_person-mass-charm-person" data-hash-target>Mass Charm Person</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 206</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 5, bard 4, mesmerist 4, occultist 4, psychic 5, shaman 5, skald 4, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one or more humanoid creatures, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like charm person, except that mass charm person affects a number of humanoid creatures whose combined Hit Dice don't exceed twice your level. If there are more potential targets than you can affect, you choose them one at a time until you reach the limit of HD you can affect. If you cast mass charm person on only one creature, you ignore the spell's HD limit.</p>
</>};
const _charnel_house = {title: "Charnel House", jsx: <><h2 id="spell-charnel_house-charnel-house">Charnel House</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 111</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/evil">evil</Link>, <Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> antipaladin 3, arcanist 5, cleric 5, mesmerist 5, oracle 5, psychic 5, sorcerer 5, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (one Tiny or larger living creature)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 20-ft. cube (S)<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> no</p><p>By sacrificing a living creature, you create the grisly illusion of viscera and gore splattered about the nearby area. When the casting time is complete, the walls drip with blood and the floor is slick with unidentifiable lumps of meat and other signs of a massacre. Anyone entering the area must attempt a Will save or be sickened for 1d6 rounds. This is a mind-affecting effect. If a creature succeeds at its save, it can see the semi-real nature of the illusion.</p>
<p>The room itself is covered in a layer of slippery, semi-real gore. Any creature attempting to walk within or through the area of gore can move at half normal speed with a DC 10 Acrobatics check. Failure means it can't move that round, and failure by 5 or more means it falls prone (see the <Link to="/skill/acrobatics">Acrobatics</Link> skill for details). Creatures that don't move on their turns don't need to attempt this check and are not considered flat-footed. A creature that succeeded at its Will save gains a +5 bonus on the Acrobatics check.</p>
</>};
const _charons_dispensation = {title: "Charon's Dispensation", jsx: <><h2 id="spell-charons_dispensation-charons-dispensation">Charon's Dispensation</h2>
<p><strong>Sources</strong> <Link to="/source/book_of_the_damned">Book of the Damned pg. 183</Link>, <Link to="/source/book_of_the_damned___volume_3_horsemen_of_the_apocalypse">Book of the Damned - Volume 3: Horsemen of the Apocalypse pg. 38</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 4, cleric 4, inquisitor 4, medium 4, mesmerist 4, oracle 4, psychic 4, shaman 4, sorcerer 4, spiritualist 4, warpriest 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (2 silver coins)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature/level<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The target of this spell gains immunity to the harmful effects of touching or drinking from the River Styx and a +4 profane bonus on saves against effects that alter or suppress memory (such as <Link to="/spell/modify_memory">modify memory</Link> or <Link to="/spell/mindwipe">mindwipe</Link>). This does not grant the target the ability to breathe water, nor does it grant any protection against creatures or mundane hazards such as rapids. The spell has no power to restore memory to a creature already suffering from an existing fugue or amnesia state.</p>
</>};
const _chastise = {title: "Chastise", jsx: <><h2 id="spell-chastise-chastise">Chastise</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, bard 1, red mantis assassin 1, skald 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You gain a +5 bonus on Bluff, Diplomacy, and Intimidate checks to convince a listener that they will get in trouble with their superiors or with the law if they don't do what you ask.</p>
<p>This spell is primarily used by the <Link to="/rule/eagle_knights">Eagle Knights</Link>, though they did not create it; <Link to="/rule/hellknights">Hellknights</Link> also use it extensively to gather information and foster cooperation.</p>
</>};
const _cheetahs_sprint = {title: "Cheetah's Sprint", jsx: <><h2 id="spell-cheetahs_sprint-cheetahs-sprint">Cheetah's Sprint</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> bloodrager 1, druid 1, hunter 1, ranger 1, shaman 1, witch 1<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round</p><p>A wild surge of energy courses through your body and propels you into a sprint. If you take a charge or run action before the end of your turn, you can move a total distance of up to 10 times your base land speed. This adjustment is an enhancement bonus. There is no effect on other modes of movement, such as burrow, climb, fly, or swim. As with other effects that increase your speed, this spell affects your jumping distance.</p>
</>};
const _chill_metal = {title: "Chill Metal", jsx: <><h2 id="spell-chill_metal-chill-metal">Chill Metal</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 254</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/cold">cold</Link>]; <strong>Level</strong> druid 2, hunter 2, occultist 2, psychic 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> metal equipment of one creature per two levels, no two of which can be more than 30 ft. apart; or 25 lbs. of metal/level, none of which can be more than 30 ft. away from any of the rest<br/><strong>Duration</strong> 7 rounds<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>Chill metal makes metal extremely cold. Unattended, nonmagical metal gets no saving throw. Magical metal is allowed a saving throw against the spell. An item in a creature's possession uses the creature's saving throw bonus unless its own is higher.</p>
<p>A creature takes cold damage if its equipment is chilled. It takes full damage if its armor, shield, or weapon is affected. The creature takes minimum damage (1 point or 2 points; see the table) if it's not wearing or wielding such an item.</p>
<p>On the first round of the spell, the metal becomes chilly and uncomfortable to touch but deals no damage. The same effect also occurs on the last round of the spell's duration. During the second (and also the next-to-last) round, icy coldness causes pain and damage. In the third, fourth, and fifth rounds, the metal is freezing cold, and causes more damage, as shown on the table below.</p>
<ScrollContainer id="spell-chill_metal--table-0"><table>
<thead>
<tr>
<th>Round</th>
<th>Metal Temperature</th>
<th>Damage</th>
</tr>
</thead>
<tbody><tr>
<td>1</td>
<td>Cold</td>
<td>None</td>
</tr>
<tr>
<td>2</td>
<td>Icy</td>
<td>1d4 points</td>
</tr>
<tr>
<td>3-5</td>
<td>Freezing</td>
<td>2d4 points</td>
</tr>
<tr>
<td>6</td>
<td>Icy</td>
<td>1d4 points</td>
</tr>
<tr>
<td>7</td>
<td>Cold</td>
<td>None</td>
</tr>
</tbody></table></ScrollContainer>
<p>Any heat intense enough to damage the creature negates cold damage from the spell (and vice versa) on a point-for-point basis. Underwater, chill metal deals no damage, but ice immediately forms around the affected metal, making it float if unattended.</p>
<p>Chill metal counters and dispels <Link to="/spell/heat_metal">heat metal</Link>.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-chill_metal--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Chill Metal</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>The damage dealt increases to 1d8 points of cold damage on rounds 2 and 6, and to 2d8 points of cold damage on rounds 3 through 5. Each round a creature takes cold damage from this spell, it also takes 1 point of Dexterity damage (Fortitude negates).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _chill_touch = {title: "Chill Touch", jsx: <><h2 id="spell-chill_touch-chill-touch">Chill Touch</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 255</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 1, bloodrager 1, magus 1, shaman 1, sorcerer 1, spiritualist 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creature or creatures touched (up to one/level)<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude partial or Will negates; see text; <strong>Spell Resistance</strong> yes</p><p>A touch from your hand, which glows with blue energy, disrupts the life force of living creatures. Each touch channels negative energy that deals 1d6 points of damage. The touched creature also takes 1 point of Strength damage unless it makes a successful Fortitude saving throw. You can use this melee touch attack up to one time per level.</p>
<p>An undead creature you touch takes no damage of either sort, but it must make a successful Will saving throw or flee as if panicked for 1d4 rounds + 1 round per caster level.</p>
</>};
const _chord_of_shards = {title: "Chord of Shards", jsx: <><h2 id="spell-chord_of_shards-chord-of-shards">Chord of Shards</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> bard 1, skald 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 15 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex negates; <strong>Spell Resistance</strong> no</p><p>During your bardic performance, you can strike a chord whose notes transform into a shower of razor sharp, crystalline shards. The shards deal 2d6 points of piercing damage to all creatures caught in the area of effect.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-chord_of_shards--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Chord of Shards</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>The damage dealt increases to 2d8 points of piercing damage and bypasses all damage reduction. Any creature damaged by the shards takes 1d8 points of sonic damage.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _circle_of_clarity = {title: "Circle of Clarity", jsx: <><h2 id="spell-circle_of_clarity-circle-of-clarity">Circle of Clarity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 7, cleric 7, oracle 7, psychic 7, shaman 8, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a crystal lens worth 100 gp)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> 20-ft.-radius emanation centered on a creature, object or point in space<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You create a magical emanation that interferes with all figments and glamers within it, giving creatures a +4 bonus on saving throws to recognize them as illusions. The emanation negates <Link to="/rule/concealment">concealment</Link> less than total concealment within the area. Perception checks to notice creatures or objects within the area gain a bonus equal to half your caster level (maximum +10). The spell is stationary if cast on a point in space. It is mobile if centered on a creature or object, though creatures or attended objects can negate the spell with a saving throw or spell resistance.</p>
</>};
const _circle_of_death = {title: "Circle of Death", jsx: <><h2 id="spell-circle_of_death-circle-of-death">Circle of Death</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 255</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/death">death</Link>]; <strong>Level</strong> arcanist 6, inquisitor 6, sorcerer 6, spiritualist 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a crushed black pearl worth 500 gp)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> several living creatures within a 40-ft.-radius burst<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>Circle of death snuffs out the life force of living creatures, killing them instantly. The spell slays 1d4 HD worth of living creatures per caster level (maximum 20d4). Creatures with the fewest HD are affected first; among creatures with equal HD, those who are closest to the burst's point of origin are affected first. No creature of 9 or more HD can be affected, and HD that are not sufficient to affect a creature are wasted.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-circle_of_death--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Circle of Death</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>The number of Hit Dice worth of creatures killed by the spell increases to 1d6 per caster level (maximum 20d6). Add your tier to the maximum HD of creatures that can be affected by the spell. (For example, at 3rd tier, a creature with 12 HD cannot be affected.)</p>
<p><em>Augmented (6th):</em> If you expend two uses of mythic power, creatures that succeed at their saves against this spell take 1d6 points of damage per tier.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _claim_identity = {title: "Claim Identity", jsx: <><h2 id="spell-claim_identity-claim-identity">Claim Identity</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> alchemist 3, antipaladin 3, arcanist 4, bard 3, druid 4, hunter 4, inquisitor 3, investigator 3, shaman 4, skald 3, sorcerer 4, witch 3, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a needle and thread)<br/><strong>Range</strong> touch<br/><strong>Target</strong> humanoid creature touched<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You steal the target's face, transforming yourself into a flawless imitation of it. All of the target's facial features, vocal cues, and identifying physical traits change, transforming it into an unremarkable member of its race and gender. You transform into a perfect likeness of the target's true form, as if affected by alter self, and gain a +10 bonus on Disguise checks to impersonate the original subject of this spell; you take no penalties on this check if the original target is of a different race, age, size, or gender.</p>
<p>Claim identity prevents any other polymorph effects from restoring the target's true face for the spell's duration, though the target can still assume other forms or faces via magic or any natural shapechanging ability.</p>
<h3 id="spell-claim_identity-greater-claim-identity">Greater Claim Identity</h3>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> alchemist 5, antipaladin 4, arcanist 6, bard 5, druid 6, hunter 6, inquisitor 5, investigator 5, shaman 6, skald 5, sorcerer 6, witch 5, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a silver needle costing 100 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> humanoid creature touched<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as per claim identity, except it transforms its target into a helpless, inanimate porcelain mask for the spell's duration. The target remains aware of everything it can see or hear while transformed. The target can't speak or move, but can still take purely mental actions (such as casting certain spells) or be targeted by spells that affect its mind.</p>
<p>Any creature donning this mask is transformed into a flawless imitation of the spell's target, as if affected by claim identity, and reverts to its natural form upon removing the mask. Any damage dealt to the mask immediately ends this spell.</p>
</>};
const _clairaudience_clairvoyance = {title: "Clairaudience/Clairvoyance", jsx: <><h2 id="spell-clairaudience_clairvoyance-clairaudienceclairvoyance">Clairaudience/Clairvoyance</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 255</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 3, bard 3, medium 2, mesmerist 3, occultist 3, psychic 3, shaman 3, skald 3, sorcerer 3, spiritualist 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, F/DF (a small horn or a glass eye)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> magical sensor<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Clairaudience/clairvoyance creates an invisible magical sensor at a specific location that enables you to hear or see (your choice) almost as if you were there. You don't need line of sight or line of effect, but the locale must be known - a place familiar to you, or an obvious one. Once you have selected the locale, the sensor doesn't move, but you can rotate it in all directions to view the area as desired. Unlike other scrying spells, this spell does not allow magically or supernaturally enhanced senses to work through it. If the chosen locale is magically dark, you see nothing. If it is naturally pitch black, you can see in a 10-foot radius around the center of the spell's effect. Clairaudience/clairvoyance functions only on the plane of existence you are currently occupying.</p>
</>};
const _clarion_call = {title: "Clarion Call", jsx: <><h2 id="spell-clarion_call-clarion-call">Clarion Call</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link>; <strong>Level</strong> arcanist 1, bard 1, cleric 1, magus 1, oracle 1, red mantis assassin 1, skald 1, sorcerer 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a piece of brass)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject of this spell gains two benefits. First, the affected creature gains the ability to create a sound like the blast of a mighty horn or trumpet simply by miming the action of sounding one. Second, the subject can speak in a booming voice that carries easily over great distances, lowering the DC of any check to hear what is said by -15. This spell is particularly prized by battlefield commanders and champions who wish to make themselves clearly heard or gain the attention of their allies or foes.</p>
</>};
const _clashing_rocks = {title: "Clashing Rocks", jsx: <><h2 id="spell-clashing_rocks-clashing-rocks">Clashing Rocks</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 210</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> arcanist 9, druid 9, sorcerer 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex partial, see text; <strong>Spell Resistance</strong> no</p><p>You create two Colossal-sized masses of rock, dirt, and stone and slam them together against a single creature between them. The clashing rocks appear up to 30 feet away from the target on opposite sides and rush toward it with a mighty grinding crash. You must make a ranged touch attack to hit the target with the rocks. The clashing rocks ignore concealment and cover, and if there is a solid barrier between the target and either of the clashing rocks, the spell has a +28 bonus on the Strength check to burst through the barrier and continue unimpeded to the target. A creature struck by the clashing rocks takes 20d6 points of bludgeoning damage and is knocked prone. If the target fails a Reflex saving throw, it is also buried under the resulting rubble as if by a <Link to="/rule/cave_ins_and_collapses">cave-in</Link>.</p>
<p>If the clashing rocks miss the target, the target still takes 10d6 points of bludgeoning damage from falling rocks and is knocked prone. A successful Reflex save reduces this damage to half and the target remains standing. Creatures other than the target that occupy the spaces where the clashing rocks appear or within their path (30 feet wide, 30 feet high, and up to 60 feet long) must also make Reflex saves or take 10d6 points of bludgeoning damage and be knocked prone (save for half and remain standing). A creature can only take damage once from the clashing rocks, no matter how many times the clashing rocks pass over a target creature.</p>
</>};
const _cleanse = {title: "Cleanse", jsx: <><h2 id="spell-cleanse-cleanse">Cleanse</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 5, inquisitor 6, oracle 5, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous</p><p>Positive energy infuses and cleanses your body. This spell cures 4d8 points of damage + 1 point per caster level (maximum +25) and ends any and all of the following adverse conditions affecting you: ability damage, blinded, confused, dazzled, deafened, diseased, exhausted, fatigued, nauseated, poisoned, and sickened. In addition, cleanse functions as <Link to="/spell/break_enchantment">break enchantment</Link> upon a single additional effect of your choice that is affecting you and that can be legally affected by this effect.</p>
<p>If used by undead or other creatures healed by negative energy, the spell cleanses with negative energy rather than positive.</p>
</>};
const _cleansing_fire = {title: "Cleansing Fire", jsx: <><h2 id="spell-cleansing_fire-cleansing-fire">Cleansing Fire</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>, <Link to="/spelldef/good">good</Link>]; <strong>Level</strong> cleric 5, inquisitor 4, oracle 5, paladin 4, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Area</strong> 30-ft. rdius emanating from the touched point<br/><strong>Duration</strong> concentration, up to 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>A ring of fire surrounds the area affected by the spell. The flames radiate heat, but not enough to damage adjacent creatures. The flames deal 2d6 points of fire damage to any creatures that pass through them (or 4d6 points of damage to undead creatures). If you manifest a portion of the ring in a square that contains a creature, that creature takes damage as if it passed through the ring.</p>
<p>The ring of flames attempts to dispel all ongoing spell effects with the evil descriptor within it, targeting each spell effect once per round as per <Link to="/spell/dispel_magic">dispel magic</Link>. Any attempt to cast a spell with the evil descriptor inside the ring of flames is targeted by a dispel magic affect that attempts to counterspell the evil spell.</p>
</>};
const _clear_grove = {title: "Clear Grove", jsx: <><h2 id="spell-clear_grove-clear-grove">Clear Grove</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 3, hunter 2, ranger 2, shaman 3, witch 3<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M/DF (a miniature hoe)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> 20-ft.-radius clearing<br/><strong>Duration</strong> 2 hours/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Trees, shrubs, and other thick vegetation move out of the spell's area. The affected area is cleared of all vegetation thick enough to provide cover or concealment. This also creates a hole in any tree canopy, allowing sunlight to pass through. Affected trees and undergrowth form a 5-foot-wide ring along the edge of the clearing, which may provide cover or concealment based on the thickness of the vegetation (at the GM's discretion).</p>
<p>This spell doesn't affect creatures of the plant type. The spell can affect vegetation altered with spells of equal or lower level (such as entangle or spike growth). When the spell ends, the trees and undergrowth move back to their original places unless they're destroyed or somehow restrained (the amount of time this takes is subject to the GM's discretion).</p>
</>};
const _clenched_fist = {title: "Clenched Fist", jsx: <><h2 id="spell-clenched_fist-clenched-fist">Clenched Fist</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 255</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> arcanist 8, psychic 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F/DF (a leather glove)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> 10-ft. hand<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>This spell functions like interposing hand, except that the hand can also push or strike one opponent that you select. The floating hand can move as far as 60 feet and can attack in the same round. Since this hand is directed by you, its ability to notice or attack invisible or concealed creatures is no better than yours.</p>
<p>The hand attacks once per round, and its attack bonus equals your caster level + your Intelligence, Wisdom, or Charisma modifier (for a wizard, cleric, or sorcerer, respectively) + 11 for the hand's Strength score (33), - 1 for being Large. The hand deals 1d8+11 points of damage on each attack, and any creature struck must make a Fortitude save (against this spell's save DC) or be stunned for 1 round. Directing the spell to a new target is a move action.</p>
<p>The clenched fist can also interpose itself as interposing hand does, or it can bull rush an opponent as forceful hand does. Its CMB for bull rush checks uses your caster level in place of its base attack bonus, with a +11 bonus for its Strength score and a +1 bonus for being Large.</p>
</>};
const _cleromancy = {title: "Cleromancy", jsx: <><h2 id="spell-cleromancy-cleromancy">Cleromancy</h2>
<p><strong>Sources</strong> <Link to="/source/occult_mysteries">Occult Mysteries pg. 50</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 3, cleric 2, druid 3, hunter 3, inquisitor 3, oracle 2, sorcerer 3, warpriest 2, wizard 3<br/><strong>Casting Time</strong> 1 full-round action<br/><strong>Components</strong> V, S, F/DF (a set of 64 chicken bones)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/caster level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Cleromancy involves casting bones and interpreting the results. Those able to arrive at the proper interpretation are granted knowledge of coming events. Roll 1d4 per caster level. Group the dice by like results, and choose one of the groups. For the duration of cleromancy, you can apply a luck bonus equal to the result of the selected dice to any d20 roll. You can apply this bonus to a number of rolls equal to the number of dice in the group. If cleromancy expires before you are able to allocate the total number of allotted bonuses, the remaining bonuses are lost.</p>
</>};
const _climbing_beanstalk = {title: "Climbing Beanstalk", jsx: <><h2 id="spell-climbing_beanstalk-climbing-beanstalk">Climbing Beanstalk</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 177</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> druid 2, hunter 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> 5-ft. square of climbable beanstalks<br/><strong>Duration</strong> instantaneous</p><p>You cause a thick, sturdy beanstalk to sprout from the ground and grow upward to a height of 10 feet + 5 feet per 2 caster levels. The growing stalk anchors itself to sturdy objects such as walls or ceilings, and grows around objects that do not fully obstruct its square (such as tree branches), but is stopped by solid obstacles. The beanstalk provides numerous hand- and footholds; its climb DC 5. The beanstalk can support up to 200 pounds plus 50 pounds per caster level, or double that amount if anchored on its upper end. If it anchors itself to a sturdy mobile object (such as a ship or a siege engine), breaking the object free requires a DC 23 Strength check or cutting through the beanstalk (hardness 2, 40 hp).</p>
<p>If the ground is capable of supporting plant life, the beanstalk continues to live as a normal plant, and it produces nutritious (if unappetizing) beans. Otherwise, the plant dies after 1d6 hours; its husk remains as durable as a small tree.</p>
</>};
const _cloak_of_chaos = {title: "Cloak of Chaos", jsx: <><h2 id="spell-cloak_of_chaos-cloak-of-chaos">Cloak of Chaos</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 255</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/chaotic">chaotic</Link>]; <strong>Level</strong> cleric 8, oracle 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a tiny reliquary worth 500 gp)<br/><strong>Range</strong> 20 ft.<br/><strong>Targets</strong> one creature/level in a 20-ft.-radius burst centered on you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> yes</p><p>A random pattern of color surrounds the subjects, protecting them from attacks, granting them resistance to spells cast by lawful creatures, and causing lawful creatures that strike the subjects to become confused. This abjuration has four effects.</p>
<p>First, each warded creature gains a +4 deflection bonus to AC and a +4 resistance bonus on saves. Unlike <Link to="/spell/protection_from_law">protection from law</Link>, the benefit of this spell applies against all attacks, not just against attacks by lawful creatures.</p>
<p>Second, each warded creature gains spell resistance 25 against lawful spells and spells cast by lawful creatures.</p>
<p>Third, the abjuration protects from possession and mental influence, just as protection from law does.</p>
<p>Finally, if a lawful creature succeeds on a melee attack against a warded creature, the offending attacker is confused for 1 round (Will save negates, as with the confusion spell, but against the save DC of cloak of chaos).</p>
</>};
const _cloak_of_dreams = {title: "Cloak of Dreams", jsx: <><h2 id="spell-cloak_of_dreams-cloak-of-dreams">Cloak of Dreams</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 6, bard 5, mesmerist 5, occultist 6, psychic 6, shaman 7, skald 5, sorcerer 6, witch 6, wizard 6<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (a rose petal and a drop of perfume)<br/><strong>Range</strong> 5 ft.<br/><strong>Area</strong> 5-ft.-radius emanation centered on you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You are surrounded by a soporific aroma that causes living creatures that begin their turn or end their movement within 5 feet of you to fall asleep for 1 minute. Creatures must save each time they begin their turn or end their movement within the cloak of dreams, even if they have previously saved against the effect. Sleeping creatures are helpless but can be awakened with a standard action or after being wounded. Creatures with the scent special quality have a -4 penalty on their saves.</p>
</>};
const _cloak_of_secrets = {title: "Cloak of Secrets", jsx: <><h2 id="spell-cloak_of_secrets-cloak-of-secrets">Cloak of Secrets</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> antipaladin 1, arcanist 1, bard 1, cleric 1, inquisitor 1, oracle 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 5-ft.-radius emanation centered on a point in space<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell forms an invisible bubble that filters all speech coming from inside the affected area so that creatures outside hear a completely different version of the conversation. The bubble also disguises lip movements to match the false conversation. Any creature listening to the conversation for at least 1 round can attempt a DC 15 Sense Motive check to realize that the apparent conversation doesn't actually make any sense. The bubble also obscures the verbal components of spells cast within the area so it's impossible to identify spells by their verbal components alone, and anyone outside the bubble attempting a Spellcraft check to identify a spell cast within the bubble takes a -5 penalty on the check. Furthermore, the bubble renders any language-dependent spells and effects used within the bubble ineffective against creatures outside the area.</p>
</>};
const _cloak_of_shade = {title: "Cloak of Shade", jsx: <><h2 id="spell-cloak_of_shade-cloak-of-shade">Cloak of Shade</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> druid 1, hunter 1, ranger 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a leaf from a shade tree)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature per level<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell provides the subject with some degree of protection from the harmful effects of the sun. The cloaked subject treats environmental heat due to sun exposure as one level less: severe heat is considered very hot conditions, while very hot is considered average temperature (see <Link to="/rule/heat_dangers">heat dangers</Link>). The cloak of shade also reduces any penalties from sunlight by 1. The spell does not, however, eliminate the effects of direct sunlight on creatures vulnerable to sunlight. Cloak of shade has no effect on environmental heat from sources other than the sun.</p>
</>};
const _cloak_of_shadows = {title: "Cloak of Shadows", jsx: <><h2 id="spell-cloak_of_shadows-cloak-of-shadows">Cloak of Shadows</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 80</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/evil">evil</Link>, <Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> antipaladin 4, arcanist 5, bard 5, mesmerist 5, skald 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You wrap yourself in a protective mantle of semi-real shadow. This grants a number of advantages: you gain concealment (20% miss chance), a +5 competence bonus on Stealth checks, and DR 5/good. This shroud of shadows also protects you from direct sunlight, negating sunlight vulnerability, sunlight powerlessness, and similar effects.</p>
<p>When you are in dim light or darkness, the first two benefits increase against foes that don't have darkvision or the see in darkness ability. Such creatures suffer a 50% miss chance (though you don't gain total concealment) and your competence bonus on Stealth checks increases to +10 with respect to such creatures.</p>
</>};
const _cloak_of_winds = {title: "Cloak of Winds", jsx: <><h2 id="spell-cloak_of_winds-cloak-of-winds">Cloak of Winds</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> arcanist 3, bloodrager 3, druid 3, hunter 3, magus 3, occultist 3, ranger 3, sorcerer 3, spiritualist 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You shroud a creature in a whirling screen of strong, howling wind. The subject is never checked or blown away by strong winds of windstorm or lesser strength (whether natural or magically created), and ranged attack rolls against the subject take a -4 penalty. Tiny or smaller creatures must succeed at a Fortitude save to successfully touch or attack the subject in melee. Failure knocks the attacker prone and pushes it 5 feet away from the subject per level of the caster. This movement can pass through the squares of other creatures without affecting them and does not provoke attacks of opportunity, but the creature takes 3d6 points of nonlethal damage, plus 1d6 if the creature strikes a solid object that blocks its movement.</p>
</>};
const _clone = {title: "Clone", jsx: <><h2 id="spell-clone-clone">Clone</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 256</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 8, sorcerer 8, witch 8, wizard 8<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (laboratory supplies worth 1,000 gp), F (special laboratory equipment costing 500 gp)<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> one clone<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell makes an inert duplicate of a creature. If the original individual has been slain, its soul immediately transfers to the clone, creating a replacement (provided that the soul is free and willing to return). The original's physical remains, should they still exist, become inert and cannot thereafter be restored to life. If the original creature has reached the end of its natural life span (that is, it has died of natural causes), any cloning attempt fails.</p>
<p>To create the duplicate, you must have a piece of flesh (not hair, nails, scales, or the like) with a volume of at least 1 cubic inch that was taken from the original creature's living body. The piece of flesh need not be fresh, but it must be kept from rotting. Once the spell is cast, the duplicate must be grown in a laboratory for 2d4 months.</p>
<p>When the clone is completed, the original's soul enters it immediately, if that creature is already dead. The clone is physically identical to the original and possesses the same personality and memories as the original. In other respects, treat the clone as if it were the original character raised from the dead, including its gaining of two permanent negative levels, just as if it had been hit by an energy-draining creature. If the subject is 1st level, it takes 2 points of Constitution drain instead (if this would reduce its Con to 0 or less, it can't be cloned). If the original creature gained permanent negative levels since the flesh sample was taken, the clone gains these negative levels as well.</p>
<p>The spell duplicates only the original's body and mind, not its equipment. A duplicate can be grown while the original still lives, or when the original soul is unavailable, but the resulting body is merely a soulless bit of inert flesh which rots if not preserved.</p>
</>};
const _cloud_of_seasickness = {title: "Cloud of Seasickness", jsx: <><h2 id="spell-cloud_of_seasickness-cloud-of-seasickness">Cloud of Seasickness</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_55_the_wormwood_mutiny">Pathfinder #55: The Wormwood Mutiny pg. 73</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> arcanist 2, cleric 2, druid 2, hunter 2, oracle 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a piece of seaweed)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> cloud spreads in 20-ft. radius, 20 ft. high<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates; see text; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em>This spell is associated with <Link to="/faith/besmara">Besmara</Link>, but there are no restrictions on its use by others.</em></p>
</blockquote>
<p>This spell functions like stinking cloud, except as noted above and that the vapors make creatures sickened instead of nauseated.</p>
<p>Cloud of seasickness can be made permanent with a <Link to="/spell/permanency">permanency</Link> spell (requiring a 9th-level caster and costing 2,500 gp). A permanent cloud of seasickness dispersed by wind reforms in 10 minutes.</p>
</>};
const _cloud_shape = {title: "Cloud Shape", jsx: <><h2 id="spell-cloud_shape-cloud-shape">Cloud Shape</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 160</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> arcanist 4, druid 4, hunter 4, ranger 4, red mantis assassin 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, M/DF (a bit of gauze and a wisp of smoke)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em><Link to="/race/sylph">Sylphs</Link> have access to the following spell.</em></p>
</blockquote>
<p>This spell functions like gaseous form, except you assume the shape of a Colossal cloud with a space of 30 feet. You choose the general appearance of the cloud (white, stormy, fluffy, flat, and so on), after which your appearance cannot be changed. Even the closest inspection cannot reveal that the cloud in question is actually a magically concealed creature. To all normal tests you are, in fact, a cloud, although a detect magic spell reveals a moderate transmutation aura on the cloud. Your fly speed in cloud form is 30 feet.</p>
</>};
const _cloudkill = {title: "Cloudkill", jsx: <><h2 id="spell-cloudkill-cloudkill">Cloudkill</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 256</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> arcanist 5, magus 5, sorcerer 5, spiritualist 5, unchained summoner 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> cloud spreads in 20-ft. radius, 20 ft. high<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude partial; see text; <strong>Spell Resistance</strong> no</p><p>This spell generates a bank of fog, similar to a fog cloud, except that its vapors are yellowish green and poisonous. These vapors automatically kill any living creature with 3 or fewer HD (no save). A living creature with 4 to 6 HD is slain unless it succeeds on a Fortitude save (in which case it takes 1d4 points of Constitution damage on your turn each round while in the cloud).</p>
<p>A living creature with 6 or more HD takes 1d4 points of Constitution damage on your turn each round while in the cloud (a successful Fortitude save halves this damage). Holding one's breath doesn't help, but creatures immune to poison are unaffected by the spell.</p>
<p>Unlike a fog cloud, the cloudkill moves away from you at 10 feet per round, rolling along the surface of the ground.</p>
<p>Figure out the cloud's new spread each round based on its new point of origin, which is 10 feet farther away from the point of origin where you cast the spell.</p>
<p>Because the vapors are heavier than air, they sink to the lowest level of the land, even pouring down den or sinkhole openings. It cannot penetrate liquids, nor can it be cast underwater.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-cloudkill--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Cloudkill</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>As a move action, you can move the cloud 10 feet in any direction. Add your tier to the spell's level and Hit Dice categories to determine its effect on creatures. (For example, at 3rd tier a creature with 6 or fewer HD gets no save, one with 7-9 HD must save or die, and one with 10 or more HD must save or take 1d4 points of Con damage.)</p>
<p><em>Augmented (6th):</em> If you expend two uses of mythic power, the spell bypasses the poison immunity of living creatures.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _codespeak = {title: "Codespeak", jsx: <><h2 id="spell-codespeak-codespeak">Codespeak</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 206</Link>, <Link to="/source/second_darkness_players_guide">Second Darkness Player's Guide pg. 26</Link>, <Link to="/source/black_markets">Black Markets pg. 24</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bard 2, medium 2, mesmerist 2, occultist 2, psychic 2, skald 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a complex rune inscribed on a slip of paper that is then placed under your tongue)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> you plus one willing creature per 2 levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Upon casting this spell, all recipients gain the ability to speak a new language. This language sounds like random, babbling syllables to anyone not under the influence of the spell, but the targets understand each other perfectly.</p>
<p>Anyone using codespeak can read and write in this new language as well. Once the spell expires, however, any coded writing suddenly appears as gibberish. If the exact same group of individuals become the targets of a codespeak spell again, cast by the same caster, they can once again read any coded writings. A dedicated codebreaker can crack such writing's code, deciphering it one page at a time with a series of DC 30 Linguistics checks.</p>
<p>Comprehend languages doesn't enable a caster to understand the language of another's codespeak spell, but it does reveal that the targets are speaking a magical language. Tongues translates codespeak normally.</p>
</>};
const _cognitive_block = {title: "Cognitive Block", jsx: <><h2 id="spell-cognitive_block-cognitive-block">Cognitive Block</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 161</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> medium 2, mesmerist 2, psychic 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You create a mental block in the target's mind, impeding the flow of his mental spellcasting process and forcing him to incorporate a thought component into any spell or spell-like ability he uses. This is in addition to any other components the spell already requires, and doesn't replace the verbal component. Spell-like abilities require this thought component, even though they normally don't need spell components.</p>
<p>As usual with thought components, this addition increases the DC of any concentration checks the target attempts by 10 unless the target takes a move action to center his mind and satisfy the spell's thought component.</p>
</>};
const _coin_shot = {title: "Coin Shot", jsx: <><h2 id="spell-coin_shot-coin-shot">Coin Shot</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 1, antipaladin 1, arcanist 1, bloodrager 1, bard 1, investigator 1, magus 1, skald 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> touch<br/><strong>Target</strong> up to three coins touched<br/><strong>Duration</strong> 10 minutes or until discharged<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes (object)</p><p>You turn up to three coins into deadly projectiles that gain the velocity of a bullet when thrown. The coins retain their normal appearance but can be used as simple thrown weapons with a range increment of 20 feet and a critical multiplier of &times;2. The transmuted coins are treated as ammunition for the purposes of drawing them. Like firearm bullets, the coins deal bludgeoning and piercing damage, and attacks with them are resolved as touch attacks within the first range increment. Regardless of whether a transmuted coin hits or misses the target, it is destroyed after the attack. Only you can make attacks with the coins, though other creatures can safely handle them without discharging the spell.</p>
<p>You can make a single ranged attack with a coin as part of casting this spell. Different types of coins create different bullet effects. Copper coins deal 1d4 points of damage. Silver coins deal 1d6 points of damage and count as silver for the purpose of overcoming damage reduction. Gold coins deal 1d8 points of damage and count as masterwork weapons. Platinum coins deal 1d10 points of damage, count as masterwork weapons, and are treated as adamantine weapons for the purposes of overcoming damage reduction and bypassing hardness. All coin bullets deal an additional 1 point of damage per 2 caster levels (to a maximum of an extra 10 points of damage at 20th level).</p>
</>};
const _cold_ice_strike = {title: "Cold Ice Strike", jsx: <><h2 id="spell-cold_ice_strike-cold-ice-strike">Cold Ice Strike</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/cold">cold</Link>]; <strong>Level</strong> arcanist 6, cleric 6, occultist 6, oracle 6, sorcerer 6, warpriest 6, wizard 6<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> 30-ft. line<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex half; <strong>Spell Resistance</strong> yes</p><p>You create a shredding flurry of ice slivers, which blast from your hand in a line. The line deals 1d6 points of cold damage per caster level (maximum 15d6).</p>
</>};
const _cold_iron_fetters = {title: "Cold Iron Fetters", jsx: <><h2 id="spell-cold_iron_fetters-cold-iron-fetters">Cold Iron Fetters</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 5, cleric 5, hunter 3, inquisitor 4, occultist 5, oracle 5, ranger 3, shaman 5, sorcerer 5, summoner 4, unchained summoner 4, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (miniature cold iron shackle)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Reflex negates; <strong>Spell Resistance</strong> no</p><p>Cold iron shackles materialize around the target's limbs, reducing each of the target's movement speeds by half. Any flying target has its maneuverability worsened by two steps (from good to poor, for example, to a minimum of clumsy maneuverability). Additionally, if the target has DR/cold iron or DR/cold iron and magic, it is unable to use supernatural or spell-like means of movement (such as dimension door, teleport, or tree meld) for the duration of the spell.</p>
</>};
const _collaborative_thaumaturgy = {title: "Collaborative Thaumaturgy", jsx: <><h2 id="spell-collaborative_thaumaturgy-collaborative-thaumaturgy">Collaborative Thaumaturgy</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 12</Link><br/><strong>School</strong> <Link to="/spelldef/universal">universal</Link>; <strong>Level</strong> arcanist 3, bard 3, cleric 3, druid 3, hunter 3, magus 3, oracle 3, skald 3, sorcerer 3, summoner 3, unchained summoner 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 immediate action<br/><strong>Components</strong> V, S, F (a bronze tuning fork)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous</p><p>You tap into the magical resonance between you and your allies to enhance one another's magic. Cast this spell when an ally casts a spell at least 1 level lower than the highest-level spell she can cast. The ally casts her spell as if one of the following metamagic feats were applied to it without increasing the spell level or casting time: <Link to="/feat/enlarge_spell">Enlarge Spell</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/feat/silent_spell">Silent Spell</Link>, or <Link to="/feat/still_spell">Still Spell</Link>. If the ally is the target of two collaborative thaumaturgy spells when casting a spell, the ally can instead apply the <Link to="/feat/empower_spell">Empower Spell</Link> metamagic feat to a spell at least 2 levels lower than the highest-level spell she can cast. Finally, if the ally is the target of three collaborative thaumaturgy spells when casting a spell, she can instead apply the <Link to="/feat/maximize_spell">Maximize Spell</Link> or <Link to="/feat/widen_spell">Widen Spell</Link> metamagic feat to a spell at least 3 levels lower than the highest-level spell she can cast. You can't target yourself with collaborative thaumaturgy.</p>
</>};
const _color_spray = {title: "Color Spray", jsx: <><h2 id="spell-color_spray-color-spray">Color Spray</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 256</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/pattern">pattern</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, magus 1, mesmerist 1, psychic 1, red mantis assassin 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (red, yellow, and blue powder or colored sand)<br/><strong>Range</strong> 15 ft.<br/><strong>Area</strong> cone-shaped burst<br/><strong>Duration</strong> instantaneous; see text<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>A vivid cone of clashing colors springs forth from your hand, causing creatures to become stunned, perhaps also blinded, and possibly knocking them unconscious. Each creature within the cone is affected according to its HD.</p>
<p><em>2 HD or less:</em> The creature is unconscious, blinded, and stunned for 2d4 rounds, then blinded and stunned for 1d4 rounds, and then stunned for 1 round. (Only living creatures are knocked unconscious.)</p>
<p><em>3 or 4 HD:</em> The creature is blinded and stunned for 1d4 rounds, then stunned for 1 round.</p>
<p><em>5 or more HD:</em> The creature is stunned for 1 round.</p>
<p>Sightless creatures are not affected by color spray.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-color_spray--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Color Spray</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 88</Link><br/>The range increases to 30 feet. Add half your tier to the spell's Hit Dice categories to determine its effects on creatures. (At 3rd tier a creature with 3 or fewer HD is unconscious, blinded, and stunned; one with 4 or 5 HD is blinded and stunned, and one with 6 or more HD is stunned.) Creatures that succeed at their saves are dazzled for 1 minute.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
